# Updated files:

## components/IntervieweeDashboard.tsx

Remove masking from phone/ID and remove "Scan to check-in" title text.

```tsx
import React, { useState, useEffect, useRef } from 'react';
import { Staff, QueueTicket } from '../types';
import { Clock, Users, QrCode, RefreshCw, Calendar, LogOut, User, Phone, CreditCard, CheckCircle2 } from 'lucide-react';
import QRCode from 'qrcode';

interface IntervieweeDashboardProps {
  staff: Staff;
  myTicket?: QueueTicket;
  ticketsAhead: number;
  onLogout: () => void;
}

const IntervieweeDashboard: React.FC<IntervieweeDashboardProps> = ({ staff, myTicket, ticketsAhead, onLogout }) => {
  const [qrCodeDataUrl, setQrCodeDataUrl] = useState('');
  const [tokenTimer, setTokenTimer] = useState(60);

  // Generate Dynamic QR Code
  useEffect(() => {
    const generateQR = async () => {
      // Token is just UserID for simple identification by QueueManager
      const token = JSON.stringify({
        uid: staff.id,
        ts: Date.now(), // timestamp to make QR look dynamic
        type: 'CHECK_IN_REQ'
      });

      try {
        const url = await QRCode.toDataURL(token, {
          width: 300,
          margin: 2,
          color: {
            dark: '#1e293b',
            light: '#ffffff'
          }
        });
        setQrCodeDataUrl(url);
      } catch (err) {
        console.error(err);
      }
    };

    generateQR();
    const interval = setInterval(() => {
      setTokenTimer((prev) => {
        if (prev <= 1) {
          generateQR();
          return 60;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(interval);
  }, [staff.id]);

  const estimatedWaitTime = ticketsAhead * 15; // Assume 15 mins per person

  return (
    <div className="min-h-[100dvh] bg-gray-50 p-4 flex flex-col items-center justify-center font-sans">

      {/* Top Bar with Logout */}
      <div className="absolute top-4 right-4">
         <button 
          onClick={onLogout} 
          className="flex items-center gap-2 text-gray-500 hover:text-red-600 bg-white px-4 py-2 rounded-full border border-gray-200 shadow-sm transition-colors text-sm font-medium"
        >
          <LogOut size={16} /> 退出
        </button>
      </div>

      <div className="w-full max-w-md space-y-6">

        {/* Header Section */}
        {/* Personal Info Card */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 flex flex-col items-center text-center relative overflow-hidden">
           <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center text-gray-400 mb-4 border-4 border-white shadow-sm">
              <User size={40} />
           </div>
           <h2 className="text-xl font-bold text-gray-800 mb-1">{staff.name}</h2>
           <div className="flex gap-4 text-xs text-gray-500 mt-2">
              <span className="flex items-center gap-1 bg-gray-50 px-2 py-1 rounded"><Phone size={10} /> {staff.phone || '无手机号'}</span>
              <span className="flex items-center gap-1 bg-gray-50 px-2 py-1 rounded"><CreditCard size={10} /> {staff.idCard || '无证件号'}</span>
           </div>
        </div>

        {/* Dynamic Content: Check-in Pending OR Checked-in Success */}
        {myTicket ? (
          /* State 2: Checked In - Show Success & Ticket */
          <div className="bg-white rounded-2xl shadow-xl border border-green-100 overflow-hidden animate-in zoom-in duration-300">
             <div className="bg-green-500 p-6 text-center text-white relative">
                <CheckCircle2 size={48} className="mx-auto mb-2 text-green-100" />
                <h3 className="text-2xl font-bold">你已核销</h3>
                <p className="text-green-100 text-sm mt-1">请耐心等待叫号</p>
             </div>
             <div className="p-8 text-center">
                <p className="text-gray-400 text-xs font-bold uppercase tracking-widest mb-2">您的排队号码</p>
                <div className="text-6xl font-black text-gray-800 font-mono tracking-tighter mb-6">{myTicket.ticketNumber}</div>

                <div className="flex justify-center gap-4 text-left bg-gray-50 p-4 rounded-xl">
                   <div>
                      <p className="text-xs text-gray-400 mb-1">前方等待</p>
                      <p className="font-bold text-gray-800">{ticketsAhead} 人</p>
                   </div>
                   <div className="w-px bg-gray-200"></div>
                   <div>
                      <p className="text-xs text-gray-400 mb-1">当前状态</p>
                      <p className={`font-bold ${myTicket.status === 'CALLED' ? 'text-green-600 animate-pulse' : 'text-blue-600'}`}>
                         {myTicket.status === 'CALLED' ? '正在叫号' : '等待中'}
                      </p>
                   </div>
                </div>
             </div>
          </div>
        ) : (
          /* State 1: Pending Scan (QR Code) */
          <div className="bg-white rounded-2xl shadow-xl border border-gray-100 p-8 flex flex-col items-center text-center animate-in fade-in slide-in-from-bottom-4">
             <div className="relative mb-6 p-2 rounded-xl border-2 border-dashed border-indigo-100 bg-indigo-50/30">
                 {qrCodeDataUrl ? (
                   <img src={qrCodeDataUrl} alt="Check-in QR" className="w-48 h-48 object-contain rounded-lg mix-blend-multiply" />
                 ) : (
                   <div className="w-48 h-48 bg-gray-100 animate-pulse rounded-lg"></div>
                 )}
                 {/* Scan Animation Line */}
                 <div className="absolute top-0 left-0 w-full h-1 bg-indigo-500/50 shadow-[0_0_15px_rgba(99,102,241,0.5)] animate-[scan_2.5s_ease-in-out_infinite]"></div>
             </div>

             <div className="w-full bg-gray-100 rounded-full h-1.5 overflow-hidden">
                <div 
                  className="bg-indigo-500 h-full transition-all duration-1000 ease-linear"
                  style={{ width: `${(tokenTimer / 60) * 100}%` }}
                />
             </div>
             <p className="text-[10px] text-gray-400 mt-2 flex items-center justify-center gap-1">
                <RefreshCw size={10} className={tokenTimer < 5 ? 'animate-spin' : ''} /> 每60秒自动刷新
             </p>
          </div>
        )}

      </div>

      <style>{`
          @keyframes scan {
            0% { top: 2%; opacity: 0; }
            10% { opacity: 1; }
            90% { opacity: 1; }
            100% { top: 98%; opacity: 0; }
          }
      `}</style>
    </div>
  );
};

export default IntervieweeDashboard;

# Specification for Updates

## 1. Configuration Data Model (`types.ts`)
- **Objective:** Define a structure to store custom prefixes for registration numbers.
- **Changes:**
  - Add `RegistrationConfig` interface with `masterPrefix` and `onSitePrefix`.
  - Update `SystemSettingsProps` to include `initialRegistrationConfig`.

## 2. System Settings UI (`components/SystemSettings.tsx`)
- **Objective:** Allow administrators to customize the prefixes.
- **UI Changes:**
  - Add a new tab or section "编号规则" (Numbering Rules).
  - Add input fields for "汇总名单前缀" (Default: 'M') and "现场报名前缀" (Default: 'S').
  - Ensure these settings are saved via the `onSave` handler.

## 3. ID Generation Logic (`components/StaffRegistration.tsx`)
- **Objective:** Apply the custom prefix when creating new records.
- **Changes:**
  - Accept a new prop `idPrefix` (string).
  - When importing CSVs, syncing from forms, or manually adding a record, generate the `registrationNumber` using this prefix + padded sequence number (e.g., `M00042`).

## 4. App Integration (`App.tsx` & `components/TrainingCheckinManager.tsx`)
- **Objective:** Wire up the config state to the components.
- **Changes in `App.tsx`:**
  - Initialize `registrationConfig` state.
  - Pass `registrationConfig.masterPrefix` to the main `StaffRegistration` component (Registration Tab).
  - Pass the full `registrationConfig` to `TrainingCheckinManager`.
- **Changes in `components/TrainingCheckinManager.tsx`:**
  - Accept `registrationConfig` prop.
  - When rendering the "On-site" `StaffRegistration` view, pass `idPrefix={registrationConfig.onSitePrefix}`.
  - When rendering the "Master List" `StaffRegistration` view, pass `idPrefix={registrationConfig.masterPrefix}`.

