}

export interface QueueTicket {
  id: string;
  ticketNumber: string; // e.g. A001
  staffId: string;
  staffName: string;
  status: QueueStatus;
  checkInTime: string;
  calledTime?: string;
}

export interface UserSession {
  userId: string;
  role: 'ADMIN' | 'USER';
  staff?: Staff;
}

export interface InterviewQuestion {
  id: string;
  text: string;
  category: string;
  difficulty: string;
}

export interface EvaluationResult {
