```tsx
import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { QueueTicket, RegistrationRecord, Staff } from '../types';
import { 
  ScanLine, 
  Camera, 
  X, 
  Search, 
  CheckCircle2, 
  AlertTriangle, 
  UserX, 
  UserCheck, 
  Clock, 
  QrCode,
  ListFilter,
  RefreshCw,
  MoreVertical,
  Trash2,
  Phone,
  User,
  Users // Added import
} from 'lucide-react';
import jsQR from 'jsqr';

interface QueueManagerProps {
  pendingStaff: Staff[]; // Kept for compatibility, but we primarily use registrationList
  queue: QueueTicket[];
  registrationList: RegistrationRecord[]; 
  onCheckIn: (staffId: string) => void;
  onUpdateTicketStatus: (ticketId: string, status: QueueTicket['status']) => void;
  onBulkCheckIn?: (staffIds: string[]) => void;
  onClearQueue?: () => void;
}

interface ScanResult {
  status: 'SUCCESS' | 'ERROR' | 'WARNING';
  title: string;
  message: string;
  data?: any;
}

const QueueManager: React.FC<QueueManagerProps> = ({ 
  queue, 
  registrationList, 
  onCheckIn, 
  onClearQueue 
}) => {
  // UI State
  const [activeTab, setActiveTab] = useState<'PENDING' | 'CHECKED'>('PENDING');
  const [searchTerm, setSearchTerm] = useState('');

  // Scanner State
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [cameraError, setCameraError] = useState('');
  const [scanResult, setScanResult] = useState<ScanResult | null>(null);

  // Refs
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);

  // --- Data Logic ---

  // 1. Identify who is checked in (Map Queue to ID)
  const checkedInIds = useMemo(() => new Set(queue.map(t => t.staffId)), [queue]);

  // 2. Compute Pending List (All Registration Records - Checked In Records)
  // We use RegistrationRecord ID or Name/Phone to match. 
  // Ideally, queue.staffId matches registrationRecord.id
  const pendingList = useMemo(() => {
    return registrationList.filter(r => !checkedInIds.has(r.id));
  }, [registrationList, checkedInIds]);

  // 3. Compute Display Lists based on Search
  const displayPending = useMemo(() => {
    const term = searchTerm.toLowerCase();
    return pendingList.filter(r => 
      r.name.toLowerCase().includes(term) || 
      (r.phone && r.phone.includes(term)) ||
      r.registrationNumber.includes(term)
    );
  }, [pendingList, searchTerm]);

  const displayChecked = useMemo(() => {
    const term = searchTerm.toLowerCase();
    // Reverse to show newest first
    return [...queue].reverse().filter(t => 
      t.staffName.toLowerCase().includes(term) || 
      t.ticketNumber.toLowerCase().includes(term)
    );
  }, [queue, searchTerm]);

  // --- Audio Feedback ---
  const playSound = (type: 'success' | 'error') => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;
      const ctx = new AudioContext();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);

      if (type === 'success') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(880, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(1760, ctx.currentTime + 0.1);
        gain.gain.setValueAtTime(0.1, ctx.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.1);
        osc.start();
        osc.stop(ctx.currentTime + 0.15);
      } else {
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(150, ctx.currentTime);
        osc.frequency.linearRampToValueAtTime(100, ctx.currentTime + 0.3);
        gain.gain.setValueAtTime(0.1, ctx.currentTime);
        gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.3);
        osc.start();
        osc.stop(ctx.currentTime + 0.3);
      }
    } catch (e) { console.error(e); }
  };

  // --- Scan Handler ---
  const handleScanCode = useCallback((code: string) => {
    // 1. Parse Code
    let targetId = code.trim();
    try {
      const parsed = JSON.parse(targetId);
      if (parsed.uid) targetId = parsed.uid;
    } catch (e) {}

    // 2. Find Record
    const record = registrationList.find(r => r.id === targetId || r.phone === targetId);

    // 3. Validation
    if (!record) {
      playSound('error');
      setScanResult({
        status: 'ERROR',
        title: '无效二维码',
        message: '未在报名名单中找到该人员信息。'
      });
      return;
    }

    if (checkedInIds.has(record.id)) {
      playSound('error');
      setScanResult({
        status: 'WARNING',
        title: '重复签到',
        message: `${record.name} 已经在 ${new Date().toLocaleTimeString()} 完成签到。`
      });
      return;
    }

    // 4. Success
    playSound('success');
    onCheckIn(record.id);
    setScanResult({
      status: 'SUCCESS',
      title: '签到成功',
      message: `${record.name} (编号:${record.registrationNumber})`,
      data: record
    });

    // Auto-close success message
    setTimeout(() => {
      setScanResult(prev => prev?.status === 'SUCCESS' ? null : prev);
    }, 2500);

  }, [registrationList, checkedInIds, onCheckIn]);

  // --- Camera Logic ---
  const tick = useCallback(() => {
    if (scanResult) {
      requestRef.current = requestAnimationFrame(tick);
      return;
    }
    if (videoRef.current && videoRef.current.readyState === videoRef.current.HAVE_ENOUGH_DATA) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      if (canvas) {
        canvas.height = video.videoHeight;
        canvas.width = video.videoWidth;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
          const code = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: "dontInvert" });

          if (code && code.data) {
             // Visual Feedback Box
             ctx.beginPath();
             ctx.lineWidth = 4;
             ctx.strokeStyle = "#10b981";
             const { topLeftCorner, topRightCorner, bottomRightCorner, bottomLeftCorner } = code.location;
             ctx.moveTo(topLeftCorner.x, topLeftCorner.y);
             ctx.lineTo(topRightCorner.x, topRightCorner.y);
             ctx.lineTo(bottomRightCorner.x, bottomRightCorner.y);
             ctx.lineTo(bottomLeftCorner.x, bottomLeftCorner.y);
             ctx.lineTo(topLeftCorner.x, topLeftCorner.y);
             ctx.stroke();

             handleScanCode(code.data);
          }
        }
      }
    }
    requestRef.current = requestAnimationFrame(tick);
  }, [handleScanCode, scanResult]);

  const toggleCamera = async () => {
    if (isCameraActive) {
      stopCamera();
    } else {
      setCameraError('');
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: "environment" } });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.setAttribute("playsinline", "true");
          await videoRef.current.play();
          setIsCameraActive(true);
          requestRef.current = requestAnimationFrame(tick);
        }
      } catch (err) {
        setCameraError('无法访问摄像头，请检查权限。');
      }
    }
  };

  const stopCamera = () => {
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    if (videoRef.current && videoRef.current.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
    setIsCameraActive(false);
  };

  useEffect(() => {
    return () => stopCamera();
  }, []);

  // --- Manual Action ---
  const handleManualCheckIn = (record: RegistrationRecord) => {
    if (checkedInIds.has(record.id)) return;
    handleScanCode(record.id);
  };

  return (
    <div className="flex flex-col h-full animate-fade-in gap-4 min-h-0">

      {/* 1. Header & Stats - Redesigned Cards */}
