          {/* Card 1: Checked In - Green */}
          <div className="bg-white p-3 md:p-4 rounded-xl border border-green-100 shadow-sm flex flex-col items-center justify-center text-center relative overflow-hidden group hover:shadow-md transition-all">
             <div className="absolute -top-2 -right-2 text-green-50 opacity-20 transform rotate-12 group-hover:scale-110 transition-transform">
                <UserCheck size={64} />
             </div>
             <p className="text-green-600 text-xs font-bold uppercase tracking-wider mb-1 flex items-center gap-1 z-10 relative">
                <UserCheck size={14} className="hidden md:block" /> 已签到
             </p>
             <p className="text-2xl md:text-3xl font-black text-gray-800 z-10 relative">{queue.length}</p>
          </div>

          {/* Card 2: Pending - Orange */}
          <div className="bg-white p-3 md:p-4 rounded-xl border border-orange-100 shadow-sm flex flex-col items-center justify-center text-center relative overflow-hidden group hover:shadow-md transition-all">
             <div className="absolute -top-2 -right-2 text-orange-50 opacity-20 transform rotate-12 group-hover:scale-110 transition-transform">
                <UserX size={64} />
             </div>
             <p className="text-orange-500 text-xs font-bold uppercase tracking-wider mb-1 flex items-center gap-1 z-10 relative">
                <UserX size={14} className="hidden md:block" /> 待签到
             </p>
             <p className="text-2xl md:text-3xl font-black text-gray-800 z-10 relative">{pendingList.length}</p>
          </div>

          {/* Card 3: Total - Indigo */}
          <div className="bg-white p-3 md:p-4 rounded-xl border border-indigo-100 shadow-sm flex flex-col items-center justify-center text-center relative overflow-hidden group hover:shadow-md transition-all">
             <div className="absolute -top-2 -right-2 text-indigo-50 opacity-20 transform rotate-12 group-hover:scale-110 transition-transform">
                <Users size={64} />
