## components/Dashboard.tsx

Update announcement widget title and customize status card for Admins.

```tsx
import React, { useMemo, useState } from 'react';
import { 
  Users, 
  Clock, 
  Megaphone, 
  Bell, 
  CheckCircle2, 
  X,
  CalendarDays, 
  Sun, 
  Moon, 
  Pin
} from 'lucide-react';
import { AttendanceRecord, QueueTicket, Announcement, Staff, Group, GroupRole } from '../types';

interface DashboardProps {
  attendanceRecords: AttendanceRecord[];
  queueData: QueueTicket[];
  announcements: Announcement[];
  isAdmin: boolean;
  groupInfo?: GroupRole;
  staffList: Staff[];
  groups: Group[];
  currentUser?: Staff;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  attendanceRecords, 
  announcements, 
  isAdmin, 
  staffList, 
  groups,
  currentUser
}) => {
  const [selectedAnnouncement, setSelectedAnnouncement] = useState<Announcement | null>(null);

  // 1. Calculate Personal Stats
  const myRecords = useMemo(() => {
    if (isAdmin) return attendanceRecords.slice(0, 5); // Admin sees recent global
    return attendanceRecords
      .filter(r => r.staffId === currentUser?.id)
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())
      .slice(0, 10);
  }, [attendanceRecords, currentUser, isAdmin]);

  const lastClockIn = useMemo(() => {
    return myRecords.find(r => r.type === 'IN');
  }, [myRecords]);

  // Admin Specific Stats
  const totalActiveStaff = useMemo(() => staffList.filter(s => s.status === 'ACTIVE').length, [staffList]);
  const todayPresence = useMemo(() => {
      const todayStr = new Date().toDateString();
      const presentIds = new Set(
          attendanceRecords
              .filter(r => r.type === 'IN' && new Date(r.timestamp).toDateString() === todayStr)
              .map(r => r.staffId)
      );
      return presentIds.size;
  }, [attendanceRecords]);

  // 2. Calculate Group Stats (Present vs Absent for TODAY)
  const groupStats = useMemo(() => {
    const todayStr = new Date().toDateString();

    return groups.map(group => {
      // Find all ACTIVE staff in this group
      const groupStaff = staffList.filter(s => s.status === 'ACTIVE' && s.roles.some(r => r.groupId === group.id));
      const total = groupStaff.length;

      // Find how many have clocked IN today
      const presentCount = groupStaff.filter(s => {
         return attendanceRecords.some(r => 
            r.staffId === s.id && 
            r.type === 'IN' && 
            new Date(r.timestamp).toDateString() === todayStr
         );
      }).length;

      return {
        id: group.id,
        name: group.name,
        total,
        present: presentCount,
        absent: total - presentCount
      };
    });
  }, [groups, staffList, attendanceRecords]);

  // 3. Sort Announcements
  const sortedAnnouncements = useMemo(() => {
    return [...announcements].sort((a, b) => {
      if (a.isSticky && !b.isSticky) return -1;
      if (!a.isSticky && b.isSticky) return 1;
      return new Date(b.date).getTime() - new Date(a.date).getTime();
    });
  }, [announcements]);

  const getCurrentGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return '早上好';
    if (hour < 18) return '下午好';
    return '晚上好';
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto">

      {/* Header & Personal Status */}
      <div className="flex flex-col md:flex-row gap-6">
        {/* Welcome Section */}
        <div className="flex-1 bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl p-6 text-white shadow-lg shadow-indigo-200">
           <div className="flex justify-between items-start">
              <div>
                 <p className="text-indigo-100 text-sm font-medium mb-1">{new Date().toLocaleDateString('zh-CN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
                 <h1 className="text-3xl font-bold mb-2">{getCurrentGreeting()}，{currentUser?.name || '管理员'}</h1>
                 <p className="opacity-90 text-sm">祝您今天工作愉快！{isAdmin ? '以下是今日考勤概况。' : '别忘了按时打卡哦。'}</p>
              </div>
              <div className="bg-white/10 p-3 rounded-full backdrop-blur-sm">
                 <Sun className="text-yellow-300" size={24} />
              </div>
           </div>
        </div>

        {/* Action / Status Card */}
        <div className="w-full md:w-80 bg-white rounded-2xl p-6 shadow-sm border border-gray-100 flex flex-col justify-between">
           {isAdmin ? (
               /* Admin View: Real-time Monitor */
               <>
                   <div>
                      <p className="text-gray-500 text-xs font-bold uppercase tracking-wider mb-2">实时考勤监控</p>
                      <div className="flex items-center gap-3">
                         <div className="w-10 h-10 rounded-full flex items-center justify-center bg-indigo-100 text-indigo-600">
                            <Users size={20} />
                         </div>
                         <div>
                            <h3 className="font-bold text-gray-800 text-lg">
                               {todayPresence} <span className="text-sm font-normal text-gray-400">/ {totalActiveStaff}</span>
                            </h3>
                            <p className="text-xs text-gray-500">今日已签到人数</p>
                         </div>
                      </div>
                   </div>

                   <div className="mt-4 pt-4 border-t border-gray-50">
                      <div className="flex justify-between text-xs mb-1">
                          <span className="text-gray-500">出勤率</span>
                          <span className="font-bold text-indigo-600">{totalActiveStaff > 0 ? Math.round((todayPresence / totalActiveStaff) * 100) : 0}%</span>
                      </div>
                      <div className="w-full bg-gray-100 rounded-full h-1.5 overflow-hidden">
                          <div className="bg-indigo-500 h-1.5 rounded-full transition-all duration-1000" style={{ width: `${totalActiveStaff > 0 ? (todayPresence / totalActiveStaff) * 100 : 0}%` }}></div>
                      </div>
                   </div>
               </>
           ) : (
               /* Staff View: Personal Status */
               <>
                   <div>
                      <p className="text-gray-500 text-xs font-bold uppercase tracking-wider mb-2">我的考勤状态</p>
                      <div className="flex items-center gap-3">
                         <div className={`w-10 h-10 rounded-full flex items-center justify-center ${lastClockIn ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-400'}`}>
                            <Clock size={20} />
                         </div>
                         <div>
                            <h3 className="font-bold text-gray-800 text-lg">
                               {lastClockIn ? new Date(lastClockIn.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : '-- : --'}
                            </h3>
                            <p className="text-xs text-gray-500">最近上班打卡</p>
                         </div>
                      </div>
                   </div>

                   <div className="mt-4 pt-4 border-t border-gray-50 flex items-center justify-between text-sm">
                      <span className="text-gray-500">今日状态</span>
                      {lastClockIn ? (
                         <span className="bg-green-100 text-green-700 px-2 py-0.5 rounded font-bold text-xs flex items-center gap-1"><CheckCircle2 size={12} /> 工作中</span>
                      ) : (
                         <span className="bg-gray-100 text-gray-500 px-2 py-0.5 rounded font-bold text-xs flex items-center gap-1"><Moon size={12} /> 未打卡</span>
                      )}
                   </div>
               </>
           )}
        </div>
      </div>

      {/* Group Attendance Stats (Grid) */}
      <div>
         <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
            <Users size={20} className="text-indigo-600" /> 各分组今日考勤概览
         </h2>
         <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            {groupStats.length === 0 ? (
               <div className="col-span-full p-8 bg-white rounded-xl text-center text-gray-400 border border-dashed border-gray-200">
                  暂无分组数据
               </div>
            ) : (
               groupStats.map(group => (
                  <div key={group.id} className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 hover:shadow-md transition-all">
                     <div className="flex justify-between items-start mb-3">
                        <h3 className="font-bold text-gray-800 truncate" title={group.name}>{group.name}</h3>
                        <span className="text-xs text-gray-400 bg-gray-50 px-1.5 py-0.5 rounded">共 {group.total} 人</span>
                     </div>
                     <div className="flex items-center gap-4">
                        <div className="flex-1">
                           <p className="text-xs text-gray-500 mb-1">已签到</p>
                           <p className="text-xl font-bold text-green-600">{group.present}</p>
                        </div>
                        <div className="w-px h-8 bg-gray-100"></div>
                        <div className="flex-1">
                           <p className="text-xs text-gray-500 mb-1">未签到</p>
                           <p className="text-xl font-bold text-gray-400">{group.absent}</p>
                        </div>
                     </div>
                     {/* Mini Progress Bar */}
                     <div className="mt-3 w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
                        <div 
                           className="h-full bg-green-500 rounded-full transition-all duration-500" 
                           style={{ width: `${group.total > 0 ? (group.present / group.total) * 100 : 0}%` }}
                        />
                     </div>
                  </div>
               ))
            )}
         </div>
      </div>

      {/* Bottom Section: Announcements & Records */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

         {/* Announcements (2/3) */}
         <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden flex flex-col">
            <div className="p-5 border-b border-gray-50 flex justify-between items-center bg-gray-50/50">
               <h3 className="font-bold text-gray-800 flex items-center gap-2">
                  <Megaphone size={18} className="text-orange-500" /> 管理公告
               </h3>
               <span className="text-xs text-gray-400">最新消息通知</span>
            </div>
            <div className="p-5 space-y-3 flex-1 overflow-y-auto max-h-[400px] custom-scrollbar">
               {sortedAnnouncements.length === 0 ? (
                  <div className="text-center py-10 text-gray-400 flex flex-col items-center">
                     <Bell size={32} className="mb-2 opacity-20" />
                     <p>暂无公告</p>
                  </div>
               ) : (
                  sortedAnnouncements.map(notice => (
                     <div 
                        key={notice.id} 
                        className={`flex gap-4 p-4 rounded-xl border transition-all cursor-pointer ${notice.isSticky ? 'bg-orange-50/50 border-orange-100' : 'bg-white border-gray-100 hover:bg-gray-50'}`}
