             </div>
          )}
        </div>
      </div>

      {/* 导入弹窗 */}
      {isImportModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg p-6 animate-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-gray-800">导入面试/排班表</h3>
              <button onClick={() => !isUploading && setIsImportModalOpen(false)} className="text-gray-400 hover:text-gray-600"><X size={20} /></button>
            </div>

            <div className="border-2 border-dashed border-gray-300 rounded-xl p-8 text-center hover:border-indigo-400 hover:bg-indigo-50 transition-colors cursor-pointer group relative overflow-hidden" onClick={() => !isUploading && fileInputRef.current?.click()}>
               {isUploading ? (
                  <div className="flex flex-col items-center justify-center h-full">
                     <Loader2 size={32} className="text-indigo-500 animate-spin mb-2" />
                     <p className="text-indigo-600 font-bold">正在导入排班数据...</p>
                  </div>
               ) : (
                  <>
                     <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                       <UploadCloud size={32} className="text-blue-500" />
                     </div>
                     <p className="font-medium text-gray-700 mb-1">点击上传或拖拽 CSV 文件</p>
                  </>
               )}
               <input type="file" ref={fileInputRef} accept=".csv,.txt" className="hidden" onChange={handleFileUpload} disabled={isUploading} />
            </div>

            <div className="mt-6 bg-gray-50 p-4 rounded-lg text-xs text-gray-500 space-y-1 border border-gray-100">
               <p className="font-bold text-gray-700 mb-2">表格格式说明：</p>
               <p>• 系统会自动识别“备注”列。</p>
               <p>• “备注”左侧为：编号、姓名、出生日期等基础信息。</p>
               <p>• “备注”<span className="text-indigo-600 font-bold">右侧的所有列</span>都会自动生成为排班日期列。</p>
               <p>• 支持自动忽略“字母”列。</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default StaffScheduleManager;
