                <th className="sticky left-[80px] top-0 z-50 bg-gray-50 border-b border-gray-200 p-3 text-xs font-bold text-gray-600 uppercase w-[120px] text-center shadow-[4px_0_8px_-2px_rgba(0,0,0,0.1)]">
                  姓名
                </th>

                {/* 展开列：隐私信息 - 仅详细模式显示 */}
                {viewMode === 'DETAILED' && (
                  <>
                    <th className="p-3 border-b border-gray-200 text-xs font-bold text-gray-600 uppercase min-w-[120px] whitespace-nowrap bg-gray-50">出生日期</th>
