               {availableViewOptions.length > 1 && (
                 <select value={viewSource} onChange={(e) => setViewSource(e.target.value)} className="bg-white border border-gray-200 text-gray-700 text-sm rounded-lg p-2 outline-none font-medium h-[38px] max-w-[150px]">
