```tsx
import React, { useState, useEffect, useRef } from 'react';
import { ScheduleData, ScheduleRow } from '../types';
import { FileSpreadsheet, Search, Trash2, X, Check, Eye, EyeOff, Download, UploadCloud, Sun, Moon, Filter, Users, Calendar, Plus, RotateCcw, LayoutTemplate, LayoutList, Loader2 } from 'lucide-react';

interface StaffScheduleManagerProps {
  scheduleData: ScheduleData;
  onUpdateData: (data: ScheduleData) => void;
}

const MOCK_CSV_DATA = `编号,字母,姓名,出生日期,年龄,现居住地址,备注,管理备注,"5.1\n【试工】","5.2\n【早班】","5.2\n【晚班】","5.3\n【全天】"`;

const StaffScheduleManager: React.FC<StaffScheduleManagerProps> = ({ scheduleData, onUpdateData }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [shiftType, setShiftType] = useState<'全天' | '上午' | '下午'>('全天');
  const [viewMode, setViewMode] = useState<'COMPACT' | 'DETAILED'>('COMPACT');

  useEffect(() => {
    if (scheduleData.rows.length === 0 && scheduleData.headers.length === 0) {
      processImport(MOCK_CSV_DATA);
    }
  }, []);

  const formatDate = (raw: string) => {
    if (!raw) return '';
    return raw.replace(/(\d{4})年(\d{1,2})月(\d{1,2})日/g, (_, y, m, d) => `${y}.${m.padStart(2, '0')}.${d.padStart(2, '0')}`);
  };

  const processImport = (content: string) => {
    const rows: string[][] = [];
    let currentRow: string[] = [];
    let currentCell = '';
    let insideQuote = false;

    for (let i = 0; i < content.length; i++) {
      const char = content[i];
      if (char === '"') {
        if (insideQuote && content[i+1] === '"') { currentCell += '"'; i++; }
        else { insideQuote = !insideQuote; }
      } else if ((char === ',' || char === '\t') && !insideQuote) {
        currentRow.push(currentCell.trim()); currentCell = '';
      } else if ((char === '\n' || char === '\r') && !insideQuote) {
        if (char === '\r' && content[i+1] === '\n') i++;
        currentRow.push(currentCell.trim());
        if (currentRow.length > 1) rows.push(currentRow);
        currentRow = []; currentCell = '';
      } else { currentCell += char; }
    }
    if (currentCell || currentRow.length > 0) { currentRow.push(currentCell.trim()); rows.push(currentRow); }

    if (rows.length < 2) return; 

    const headerRow = rows[0];
    const idx = {
      id: headerRow.findIndex(h => h.includes('编号')),
      name: headerRow.findIndex(h => h.includes('姓名')),
      dob: headerRow.findIndex(h => h.includes('出生日期')),
      age: headerRow.findIndex(h => h.includes('年龄')),
      address: headerRow.findIndex(h => h.includes('地址')),
      notes: headerRow.findIndex(h => h.includes('备注')),
      mgmtNotes: headerRow.findIndex(h => h.includes('管理备注')),
    };
    if (idx.id === -1) idx.id = 0; if (idx.name === -1) idx.name = 2;

    const dynamicStartIndex = Math.max(idx.notes, idx.mgmtNotes) + 1;
    const dynamicHeaders: string[] = [];
    if (dynamicStartIndex < headerRow.length) {
      for (let i = dynamicStartIndex; i < headerRow.length; i++) {
        let cleanHeader = headerRow[i].replace(/^"|"$/g, '').trim();
        if (cleanHeader) dynamicHeaders.push(cleanHeader);
      }
    }

    const newRows: ScheduleRow[] = [];
    for (let i = 1; i < rows.length; i++) {
      const cols = rows[i];
      if (cols.length < 2) continue;
      const scheduleMap: Record<string, string> = {};
      dynamicHeaders.forEach((header, index) => {
        const val = cols[dynamicStartIndex + index]?.trim();
        if (val) scheduleMap[header] = (val !== '√' && val !== '上' && val !== '下') ? '√' : val;
      });
      newRows.push({
        id: crypto.randomUUID(),
        staffId: cols[idx.id] || '',
        name: cols[idx.name] || '',
        dob: formatDate(cols[idx.dob] || ''),
        age: cols[idx.age] || '',
        address: cols[idx.address] || '',
        notes: cols[idx.notes] || '',
        managementNotes: cols[idx.mgmtNotes] || '', 
        schedule: scheduleMap,
        isTalent: false,
        talentNotes: ''
      });
    }
    onUpdateData({ headers: ['编号', '姓名', '出生日期', '年龄', '现居住地址', '备注', '管理备注'], dynamicHeaders: dynamicHeaders, rows: newRows });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    setTimeout(() => {
        const reader = new FileReader();
        reader.onload = (evt) => {
          processImport(evt.target?.result as string);
          setIsImportModalOpen(false);
          setIsUploading(false);
        };
        reader.readAsText(file); 
    }, 1500);
  };

  const handleDeleteRow = (rowId: string) => {
    if (confirm("确定要删除该人员吗？")) {
      onUpdateData({ ...scheduleData, rows: scheduleData.rows.filter(r => r.id !== rowId) });
    }
  };

  const handleClearAll = () => {
    if (confirm("确定要清空所有列表数据吗？")) {
      onUpdateData({ ...scheduleData, rows: [] });
    }
  };

  const handleAddColumn = () => {
    if (!startDate) return;
    const start = new Date(startDate);
    const end = endDate ? new Date(endDate) : start;
    const newHeaders = [...scheduleData.dynamicHeaders];
    for (let d = start; d <= end; d.setDate(d.getDate() + 1)) {
      const headerName = `${d.getMonth() + 1}.${d.getDate()}\n【${shiftType}】`;
      if (!newHeaders.includes(headerName)) newHeaders.push(headerName);
    }
    onUpdateData({ ...scheduleData, dynamicHeaders: newHeaders });
  };

  const handleExport = () => {
    const allHeaders = ['编号', '姓名', '出生日期', '年龄', '现居住地址', '备注', '管理备注', ...scheduleData.dynamicHeaders.map(h => h.replace(/\n/g, ' '))];
    const csvRows = scheduleData.rows.map(row => {
      const fixedData = [row.staffId, row.name, row.dob, row.age, row.address, row.notes, row.managementNotes || ''];
      const dynamicData = scheduleData.dynamicHeaders.map(h => row.schedule[h] || '');
      return [...fixedData, ...dynamicData].map(cell => `"${String(cell).replace(/"/g, '""')}"`).join(',');
    });
    const csvContent = "\ufeff" + [allHeaders.join(','), ...csvRows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `STAFF面试表_${new Date().toLocaleDateString()}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRemoveColumn = (header: string) => {
    if (confirm(`确定删除列 "${header.replace('\n', ' ')}" 吗？`)) {
       onUpdateData({ ...scheduleData, dynamicHeaders: scheduleData.dynamicHeaders.filter(h => h !== header) });
    }
  };

  const toggleCell = (rowId: string, header: string) => {
    const newRows = scheduleData.rows.map(row => {
      if (row.id === rowId) {
        const currentVal = row.schedule[header];
        let nextVal = (!currentVal) ? '√' : (currentVal === '√' ? '上' : (currentVal === '上' ? '下' : '')); 
        return { ...row, schedule: { ...row.schedule, [header]: nextVal } };
      }
      return row;
    });
    onUpdateData({ ...scheduleData, rows: newRows });
  };

  const renderCellContent = (value: string) => {
    if (value === '√') return <div className="flex items-center justify-center w-full h-full bg-green-50 text-green-600 font-bold"><Check size={20} strokeWidth={3} /></div>;
    if (value === '上') return <div className="flex items-center justify-center w-full h-full bg-blue-50 text-blue-600 font-bold"><Sun size={20} /></div>;
    if (value === '下') return <div className="flex items-center justify-center w-full h-full bg-orange-50 text-orange-600 font-bold"><Moon size={20} /></div>;
    return <div className="w-full h-full"></div>;
  };

  const filteredRows = scheduleData.rows.filter(row => row.name.includes(searchTerm) || row.staffId.includes(searchTerm)).sort((a, b) => a.name.localeCompare(b.name, 'zh-CN'));

  return (
    <div className="space-y-6 animate-fade-in pb-10">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100 flex items-center justify-between">
           <div><p className="text-xs text-gray-400 font-bold uppercase tracking-wider mb-1">面试人员总数</p><h2 className="text-2xl font-bold text-gray-800">{scheduleData.rows.length} <span className="text-sm text-gray-400 font-normal">人</span></h2></div>
           <div className="p-3 bg-blue-50 rounded-lg text-blue-600"><Users size={20} /></div>
        </div>
        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100 flex items-center justify-between">
           <div><p className="text-xs text-gray-400 font-bold uppercase tracking-wider mb-1">当前搜索结果</p><h2 className="text-2xl font-bold text-gray-800">{filteredRows.length} <span className="text-sm text-gray-400 font-normal">人</span></h2></div>
           <div className="p-3 bg-indigo-50 rounded-lg text-indigo-600"><Filter size={20} /></div>
        </div>
      </div>

      <div className="bg-white p-3 rounded-xl shadow-sm border border-gray-200 flex flex-col md:flex-row items-center gap-3 sticky top-16 z-20">
         <div className="flex items-center gap-2 w-full md:w-auto">
            <div className="relative flex-1 max-w-sm"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" /><input type="text" placeholder="搜索姓名或编号..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-gray-50 text-sm rounded-lg pl-9 pr-4 py-2.5 border border-transparent focus:bg-white focus:border-indigo-300 outline-none" /></div>
            <button onClick={() => setViewMode(viewMode === 'COMPACT' ? 'DETAILED' : 'COMPACT')} className={`flex items-center gap-2 px-3 py-2.5 rounded-lg border transition-all shadow-sm ${viewMode === 'DETAILED' ? 'bg-indigo-600 text-white' : 'bg-white text-gray-600 hover:bg-gray-50'}`}>{viewMode === 'DETAILED' ? <LayoutList size={18} /> : <LayoutTemplate size={18} />}</button>
         </div>
         <div className="w-px h-8 bg-gray-200 hidden md:block mx-1"></div>
         <div className="flex items-center gap-2 flex-1 overflow-x-auto w-full md:w-auto no-scrollbar">
            <div className="flex items-center gap-2 bg-gray-50 px-3 py-1.5 rounded-lg border border-gray-200">
               <Calendar size={14} className="text-gray-400" /><input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="bg-transparent text-xs border-b border-gray-300 outline-none w-24 text-gray-700" /><span className="text-gray-400">-</span><input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="bg-transparent text-xs border-b border-gray-300 outline-none w-24 text-gray-700" />
            </div>
            <select value={shiftType} onChange={(e) => setShiftType(e.target.value as any)} className="bg-gray-50 text-xs border border-gray-200 rounded-lg px-2 py-2.5 outline-none"><option value="全天">全天</option><option value="上午">上午</option><option value="下午">下午</option></select>
            <button onClick={handleAddColumn} disabled={!startDate} className="flex items-center gap-1 bg-indigo-600 text-white px-3 py-2 rounded-lg text-xs font-medium hover:bg-indigo-700 disabled:opacity-50"><Plus size={14} /> 添加</button>
         </div>
         <div className="flex items-center gap-2 w-full md:w-auto justify-end">
            <button onClick={handleClearAll} className="p-2.5 rounded-lg text-gray-500 bg-gray-50 hover:bg-red-50 hover:text-red-600"><RotateCcw size={18} /></button>
            <button onClick={() => setIsImportModalOpen(true)} className="p-2.5 rounded-lg text-gray-500 bg-gray-50 hover:bg-gray-100"><UploadCloud size={18} /></button>
            <button onClick={handleExport} className="p-2.5 rounded-lg text-gray-500 bg-gray-50 hover:bg-gray-100"><Download size={18} /></button>
         </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col overflow-hidden h-[calc(100vh-320px)] w-full">
        <div className="overflow-auto flex-1 custom-scrollbar">
          <table className="w-full text-left border-collapse">
            <thead className="bg-gray-50 sticky top-0 z-50 shadow-sm">
              <tr>
                <th className="sticky left-0 top-0 z-50 bg-gray-50 border-b border-gray-200 p-3 text-xs font-bold text-gray-600 w-[80px] text-center shadow-[1px_0_0_0_#e5e7eb]">编号</th>
                <th className="sticky left-[80px] top-0 z-50 bg-gray-50 border-b border-gray-200 p-3 text-xs font-bold text-gray-600 w-[120px] text-center shadow-[4px_0_8px_-2px_rgba(0,0,0,0.1)]">姓名</th>
                {viewMode === 'DETAILED' && <><th className="p-3 border-b border-gray-200 text-xs font-bold text-gray-600 min-w-[120px]">出生日期</th><th className="p-3 border-b border-gray-200 text-xs font-bold text-gray-600 min-w-[60px]">年龄</th><th className="p-3 border-b border-gray-200 text-xs font-bold text-gray-600 min-w-[200px]">现居住地址</th></>}
                <th className="p-3 border-b border-gray-200 text-xs font-bold text-gray-600 min-w-[200px]">备注</th>
                <th className="p-3 border-b border-gray-200 text-xs font-bold text-gray-600 min-w-[180px]">管理备注</th>
                {scheduleData.dynamicHeaders.map((header) => (<th key={header} className="p-2 border-b border-gray-200 min-w-[90px] text-center bg-gray-50 group border-l border-gray-100"><div className="flex flex-col items-center justify-center gap-0.5"><span className="text-[11px] font-bold text-gray-700 whitespace-pre-line leading-tight">{header}</span><button onClick={() => handleRemoveColumn(header)} className="text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100"><Trash2 size={10} /></button></div></th>))}
                <th className="p-3 border-b border-gray-200 text-xs font-bold text-gray-600 w-[80px] text-center">操作</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 bg-white">
              {filteredRows.map((row) => (
                <tr key={row.id} className="group hover:bg-gray-50 transition-colors">
                  <td className="sticky left-0 z-40 bg-white group-hover:bg-gray-50 border-b border-gray-100 p-2 text-center text-xs font-mono text-gray-400 shadow-[1px_0_0_0_#f3f4f6]">{row.staffId}</td>
                  <td className="sticky left-[80px] z-40 bg-white group-hover:bg-gray-50 border-b border-gray-100 p-2 text-center shadow-[4px_0_8px_-2px_rgba(0,0,0,0.06)]"><span className="font-semibold text-gray-800 text-sm">{row.name}</span></td>
                  {viewMode === 'DETAILED' && <><td className="p-3 text-sm text-gray-600">{row.dob}</td><td className="p-3 text-sm text-gray-600">{row.age}</td><td className="p-3 text-sm text-gray-600 truncate" title={row.address}>{row.address}</td></>}
                  <td className="p-3 text-sm text-gray-500"><p className="line-clamp-2" title={row.notes}>{row.notes || '-'}</p></td>
                  <td className="p-2 text-sm"><input type="text" value={row.managementNotes || ''} onChange={(e) => { const newRows = scheduleData.rows.map(r => r.id === row.id ? { ...r, managementNotes: e.target.value } : r); onUpdateData({ ...scheduleData, rows: newRows }); }} className="w-full bg-transparent border-b border-transparent focus:border-indigo-400 outline-none text-indigo-700 text-sm py-1 px-1" placeholder="点击输入..." /></td>
                  {scheduleData.dynamicHeaders.map((header) => (<td key={header} className="p-0 border-b border-gray-100 border-l border-gray-50 cursor-pointer h-[52px] relative min-w-[90px]" onClick={() => toggleCell(row.id, header)}><div className="w-full h-full flex items-center justify-center hover:bg-gray-100/50 transition-colors">{renderCellContent(row.schedule[header] || '')}</div></td>))}
                  <td className="p-2 border-b border-gray-100 border-l border-gray-50 text-center"><button onClick={() => handleDeleteRow(row.id)} className="text-gray-300 hover:text-red-500 p-2"><Trash2 size={16} /></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isImportModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg p-6 animate-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-6"><h3 className="text-xl font-bold text-gray-800">导入面试/排班表</h3><button onClick={() => !isUploading && setIsImportModalOpen(false)}><X size={20} className="text-gray-400" /></button></div>
            <div className="border-2 border-dashed border-gray-300 rounded-xl p-8 text-center hover:border-indigo-400 hover:bg-indigo-50 transition-colors cursor-pointer group" onClick={() => !isUploading && fileInputRef.current?.click()}>
               {isUploading ? <div className="flex flex-col items-center justify-center"><Loader2 size={32} className="text-indigo-500 animate-spin mb-2" /><p className="text-indigo-600 font-bold">正在导入排班数据...</p></div> : <><div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform"><UploadCloud size={32} className="text-blue-500" /></div><p className="font-medium text-gray-700 mb-1">点击上传或拖拽 CSV 文件</p></>}
               <input type="file" ref={fileInputRef} accept=".csv,.txt" className="hidden" onChange={handleFileUpload} disabled={isUploading} />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default StaffScheduleManager;
