```tsx
import React, { useState, useMemo } from 'react';
import { Staff, Group, RegistrationRecord, GroupRole, PermissionSettings } from '../types';
import { 
  Users, 
  Briefcase, 
  Plus, 
  Trash2, 
  Edit2, 
  Search, 
  Shield, 
  UserPlus, 
  X,
  AlertTriangle,
  User,
  Check,
  FileText,
  CreditCard,
  Phone,
  FileSpreadsheet,
  CheckSquare,
  Square,
  Calendar,
  Loader2
} from 'lucide-react';

interface OutsourcedManagerProps {
  staffList: Staff[];
  groups: Group[];
  registrationList: RegistrationRecord[];
  onSiteRecords: RegistrationRecord[];
  permissionSettings: PermissionSettings;
  onUpdateStaff: (staff: Staff) => void;
  onAddStaff: (staff: Staff) => void;
  onBatchAddStaff: (staffList: Staff[]) => void;
  onAddGroup: (group: Group) => void;
  onUpdateGroup: (group: Group) => void;
  onDeleteGroup: (groupId: string) => void;
}

const PENDING_GROUP_ID = 'g_pending_allocation';

const maskPhone = (phone?: string): string => {
  if (!phone || phone.length < 7) return phone || '';
  return `${phone.substring(0, 3)}****${phone.substring(phone.length - 4)}`;
};

const maskIdCard = (idCard?: string): string => {
  if (!idCard || idCard.length < 8) return idCard || '';
  return `${idCard.substring(0, 3)}***********${idCard.substring(idCard.length - 4)}`;
};

const OutsourcedManager: React.FC<OutsourcedManagerProps> = ({
  staffList,
  groups,
  registrationList,
  onSiteRecords,
  permissionSettings,
  onUpdateStaff,
  onAddStaff,
  onBatchAddStaff,
  onAddGroup,
  onUpdateGroup,
  onDeleteGroup
}) => {
  const [selectedGroupId, setSelectedGroupId] = useState<string | null>(null);
  const [isGroupModalOpen, setIsGroupModalOpen] = useState(false);
  const [editingGroup, setEditingGroup] = useState<Group | null>(null);
  const [isAddMemberModalOpen, setIsAddMemberModalOpen] = useState(false);
  const [addMemberSearchTerm, setAddMemberSearchTerm] = useState('');

  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [newStaffData, setNewStaffData] = useState({ name: '', phone: '', idCard: '' });

  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [importCandidates, setImportCandidates] = useState<RegistrationRecord[]>([]);
  const [selectedCandidateIds, setSelectedCandidateIds] = useState<Set<string>>(new Set());

  const [groupSearchTerm, setGroupSearchTerm] = useState('');

  const selectedGroup = useMemo(() => 
    groups.find(g => g.id === selectedGroupId) || groups[0] || null
  , [groups, selectedGroupId]);

  if (!selectedGroupId && groups.length > 0) {
    setSelectedGroupId(groups[0].id);
  }

  const filteredGroupStaff = useMemo(() => {
    if (!selectedGroup) return [];
    let staffInGroup = staffList.filter(s => s.status === 'ACTIVE');
    if (selectedGroup.id === PENDING_GROUP_ID) {
       staffInGroup = staffInGroup.filter(s => s.roles.length === 0 || s.roles.some(r => r.groupId === PENDING_GROUP_ID));
    } else {
       staffInGroup = staffInGroup.filter(s => s.roles.some(r => r.groupId === selectedGroup.id));
    }
    const term = groupSearchTerm.toLowerCase();
    if (term) return staffInGroup.filter(s => s.name.toLowerCase().includes(term) || (s.phone && s.phone.includes(term)));
    return staffInGroup;
  }, [staffList, selectedGroup, groupSearchTerm]);

  const leaders = useMemo(() => {
    if (!selectedGroup) return [];
    return filteredGroupStaff.filter(s => s.roles.find(r => r.groupId === selectedGroup.id)?.isLeader);
  }, [filteredGroupStaff, selectedGroup]);

  const members = useMemo(() => {
    if (!selectedGroup) return [];
    return filteredGroupStaff.filter(s => !s.roles.find(r => r.groupId === selectedGroup.id)?.isLeader);
  }, [filteredGroupStaff, selectedGroup]);

  const availableStaff = useMemo(() => {
    if (!selectedGroup) return [];
    const term = addMemberSearchTerm.toLowerCase();
    return staffList.filter(s => 
      s.status === 'ACTIVE' && 
      !s.roles.some(r => r.groupId === selectedGroup.id) &&
      (s.name.toLowerCase().includes(term) || (s.phone && s.phone.includes(term)))
    );
  }, [staffList, selectedGroup, addMemberSearchTerm]);

  const handleCreateGroup = () => { setEditingGroup({ id: crypto.randomUUID(), name: '', description: '' }); setIsGroupModalOpen(true); };
  const handleEditGroup = (group: Group) => { setEditingGroup({ ...group }); setIsGroupModalOpen(true); };
  const handleSaveGroup = () => {
    if (!editingGroup || !editingGroup.name.trim()) return;
    if (groups.find(g => g.id === editingGroup.id)) onUpdateGroup(editingGroup);
    else { onAddGroup(editingGroup); setSelectedGroupId(editingGroup.id); }
    setIsGroupModalOpen(false); setEditingGroup(null);
  };
  const handleDeleteGroupClick = (id: string) => {
    const hasMembers = staffList.some(s => s.roles.some(r => r.groupId === id));
    if (hasMembers) return alert('该分组下仍有成员，无法删除。请先移除成员。');
    if (confirm('确定要删除此分组吗？')) { onDeleteGroup(id); if (selectedGroupId === id) setSelectedGroupId(null); }
  };
  const handleRemoveMember = (staff: Staff, groupId: string) => {
    if (confirm(`确定将 ${staff.name} 移出该组吗？`)) {
      const newRoles = staff.roles.filter(r => r.groupId !== groupId);
      onUpdateStaff({ ...staff, roles: newRoles });
    }
  };
  const handleToggleLeader = (staff: Staff, groupId: string) => {
    const newRoles = staff.roles.map(r => r.groupId === groupId ? { ...r, isLeader: !r.isLeader } : r);
    onUpdateStaff({ ...staff, roles: newRoles });
  };
  const handleAddExistingMember = (staff: Staff) => {
    if (!selectedGroup) return;
    const newRole: GroupRole = { groupId: selectedGroup.id, groupName: selectedGroup.name, isLeader: false };
    const updatedRoles = staff.roles.filter(r => r.groupId !== PENDING_GROUP_ID);
    onUpdateStaff({ ...staff, status: 'ACTIVE', roles: [...updatedRoles, newRole] });
  };

  const handleOpenImportModal = () => {
    const allRegistrationSources = [...registrationList, ...onSiteRecords];
    const uniqueCandidatesMap = new Map<string, RegistrationRecord>();
    allRegistrationSources.forEach(reg => {
      const key = reg.idCard || reg.phone || reg.name;
      if (key && !uniqueCandidatesMap.has(key)) {
        const existsInStaff = staffList.some(s => (s.idCard && reg.idCard && s.idCard === reg.idCard) || (s.phone && reg.phone && s.phone === reg.phone) || (s.name === reg.name && (!reg.phone || s.phone === reg.phone)));
        if (!existsInStaff) uniqueCandidatesMap.set(key, reg);
      }
    });
    const candidates = Array.from(uniqueCandidatesMap.values());
    if (candidates.length === 0) return alert('未发现可导入的新报名数据 (所有报名人员均已在员工列表中)');
    setImportCandidates(candidates); setSelectedCandidateIds(new Set(candidates.map(c => c.id))); setIsImportModalOpen(true);
  };

  const handleToggleCandidate = (id: string) => {
    const newSet = new Set(selectedCandidateIds);
    if (newSet.has(id)) newSet.delete(id); else newSet.add(id);
    setSelectedCandidateIds(newSet);
  };
  const handleToggleAllCandidates = () => {
    if (selectedCandidateIds.size === importCandidates.length) setSelectedCandidateIds(new Set());
    else setSelectedCandidateIds(new Set(importCandidates.map(c => c.id)));
  };

  const handleConfirmImport = () => {
    const selected = importCandidates.filter(c => selectedCandidateIds.has(c.id));
    if (selected.length === 0) return;
    setIsImporting(true);
    setTimeout(() => {
        const newStaff: Staff[] = selected.map(reg => ({
           id: crypto.randomUUID(), name: reg.name, phone: reg.phone || '', idCard: reg.idCard || '',
           avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${reg.name}`, status: 'ACTIVE', roles: [], joinDate: new Date().toISOString().split('T')[0]
        }));
        onBatchAddStaff(newStaff); setIsImportModalOpen(false); setImportCandidates([]); setSelectedCandidateIds(new Set()); setIsImporting(false);
    }, 1200);
  };

  const handleCreateNewStaff = () => {
     if (!newStaffData.name) return alert('请输入姓名');
     const newStaff: Staff = {
        id: crypto.randomUUID(), name: newStaffData.name, phone: newStaffData.phone, idCard: newStaffData.idCard,
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${newStaffData.name}`, status: 'ACTIVE', roles: [], joinDate: new Date().toISOString().split('T')[0]
     };
     onAddStaff(newStaff); setIsCreateModalOpen(false); setNewStaffData({ name: '', phone: '', idCard: '' });
  };

  const renderStaffCard = (staff: Staff) => {
    const isPendingGroupSelected = selectedGroup?.id === PENDING_GROUP_ID;
    const roleInCurrentGroup = staff.roles.find(r => r.groupId === selectedGroup?.id);
    const isLeaderInCurrentGroup = roleInCurrentGroup?.isLeader || false;
    let roleDisplay = '成员 (STAFF)';
    if (isPendingGroupSelected) roleDisplay = '待分配'; else if (isLeaderInCurrentGroup) roleDisplay = '编外 (LEADER)';
    const shouldShowSensitive = permissionSettings.showSensitiveInfo;

    return (
      <div key={staff.id} className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm hover:shadow-lg hover:border-indigo-200 transition-all flex flex-col relative text-left">
