       }
    });
    const timelineChartData = Object.keys(timelineData).map(k => ({ name: k, count: timelineData[k] })).sort((a,b) => parseInt(a.name) - parseInt(b.name));

    return {
      checkInCount,
      totalRegistered,
      checkInRate: totalRegistered > 0 ? Math.round((checkInCount / totalRegistered) * 100) : 0,
