import React, { useState, useEffect } from 'react';
import { Staff, QueueTicket } from '../types';
import { Clock, RefreshCw, LogOut, Sparkles, Ticket } from 'lucide-react';
import QRCode from 'qrcode';

interface IntervieweeDashboardProps {
  staff: Staff;
  myTicket?: QueueTicket;
  ticketsAhead: number;
  onLogout: () => void;
}

const IntervieweeDashboard: React.FC<IntervieweeDashboardProps> = ({ staff, myTicket, ticketsAhead, onLogout }) => {
  const [qrCodeDataUrl, setQrCodeDataUrl] = useState('');
  const [tokenTimer, setTokenTimer] = useState(60);

  // Generate Dynamic QR Code
  useEffect(() => {
    const generateQR = async () => {
      // Simulate a secure dynamic token: UserID + Timestamp
      const token = JSON.stringify({
        uid: staff.id,
        ts: Date.now(),
        type: 'CHECK_IN_REQ'
      });

      try {
        const url = await QRCode.toDataURL(token, {
          width: 300,
          margin: 2,
          color: {
            dark: '#1e293b',
            light: '#ffffff'
          }
        });
        setQrCodeDataUrl(url);
      } catch (err) {
        console.error(err);
      }
    };

    generateQR();
    const interval = setInterval(() => {
      setTokenTimer((prev) => {
        if (prev <= 1) {
          generateQR();
          return 60;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(interval);
  }, [staff.id]);

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans relative overflow-hidden">
      {/* Background decoration */}
