      {/* Main Card Container */}
      <div className="relative z-10 flex-1 px-4 pb-8 flex flex-col justify-center max-w-md mx-auto w-full">

         {myTicket ? (
            // --- TICKET VIEW ---
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden flex flex-col animate-in zoom-in duration-300 relative">
