                     {myTicket.status === 'CALLED' ? (
                        <div className="bg-white/20 p-3 rounded-full mb-3 animate-bounce">
                           <Sparkles size={32} />
                        </div>
                     ) : (
                        <div className="bg-white/20 p-3 rounded-full mb-3">
                           <Ticket size={32} />
