                  {/* Stats - Only show if waiting */}
                  {myTicket.status === 'WAITING' && (
                     <div className="w-full bg-gray-50 rounded-2xl p-4 border border-gray-100 flex justify-around items-center">
                        <div className="text-center">
                           <p className="text-xs text-gray-400 mb-1">前方等待</p>
                           {ticketsAhead > 0 ? (
                              <p className="text-xl font-bold text-gray-800">{ticketsAhead} <span className="text-xs font-normal text-gray-500">人</span></p>
