                              <p className="text-lg font-bold text-green-600">即将叫号</p>
                           )}
                        </div>
                        {ticketsAhead > 0 && (
                           <>
                              <div className="w-px h-8 bg-gray-200"></div>
                              <div className="text-center">
                                 <p className="text-xs text-gray-400 mb-1">预计等待</p>
