                     <div className="absolute top-0 left-0 w-full h-1 bg-indigo-500/50 shadow-[0_0_15px_rgba(99,102,241,0.5)] animate-[scan_2.5s_ease-in-out_infinite] rounded-full pointer-events-none"></div>
                  </div>

                  <h2 className="text-xl font-bold text-gray-800 mb-2">请出示二维码</h2>
