          onBatchAddStaff={handleBatchAddStaffFromReg}
          onManageForm={handleNavigateToForm}
          permissionSettings={permissionSettings}
          session={session}
          registrationConfig={registrationConfig}
        />;

      case 'form_manager':
        return <FormManager 
          forms={forms} 
          onCreateForm={handleCreateForm} 
          onDeleteForm={handleDeleteForm} 
          onSelectForm={(id, mode) => { setSelectedFormId(id); if (mode === 'SIMULATE') { setActiveTab('public_view_simulation'); } else { setDesignerMode(mode); setActiveTab('form_designer'); } }} 
          onToggleStatus={handleToggleFormStatus}
        />;
      case 'outsourced':
        return <OutsourcedManager 
          permissionSettings={permissionSettings}
          staffList={staffList} 
          groups={groups} 
          registrationList={registrationList} 
          onSiteRecords={onSiteRecords} 
          onUpdateStaff={handleUpdateStaff} 
          onAddStaff={handleAddStaff} 
          onBatchAddStaff={handleBatchAddStaffFromReg}
          onAddGroup={handleAddGroup} 
          onUpdateGroup={handleUpdateGroup} 
          onDeleteGroup={handleDeleteGroup} 
        />;
      case 'announcements':
        return <AnnouncementManager currentUserRole={session?.role || 'USER'} currentUserGroups={session?.staff?.roles || []} announcements={announcements} onAddAnnouncement={(a) => setAnnouncements([a, ...announcements])} onDeleteAnnouncement={(id) => setAnnouncements(announcements.filter(a => a.id !== id))} currentUserName={session?.staff?.name || '管理员'} />;
      case 'settings':
        return <SystemSettings 
          onSave={handleSaveSettings} 
          initialDomain={systemDomain} 
          initialAttendanceConfig={attendanceConfig} 
          initialPermissionSettings={permissionSettings}
          initialLoginConfig={loginConfig}
          initialRegistrationConfig={registrationConfig}
          adminUsers={adminUsers}
          onAddAdmin={handleAddAdmin}
          onDeleteAdmin={handleDeleteAdmin}
          onUpdateAdminPassword={handleUpdateAdminPassword}
        />;
      default:
        return <div className="p-10 text-center text-gray-500">功能开发中...</div>;
    }
  };

  if (activeTab === 'public_view_simulation' && selectedFormId) {
     const form = forms.find(f => f.id === selectedFormId);
     if (form) return <PublicDynamicForm form={form} onSubmit={handleFormSubmit} onCancel={() => { if (session) { if (designerMode === 'PREVIEW') setActiveTab('form_designer'); else setActiveTab('form_manager'); } else setActiveTab('login'); }} />;
  }

  if (!session) return <Login staffList={staffList} registrationList={registrationList} onSiteRecords={onSiteRecords} onLogin={handleLogin} adminUsers={adminUsers} loginConfig={loginConfig} />;

  const isLeader = session.role === 'USER' && session.staff?.roles.some(r => r.isLeader);
  const canScanCheckIn = permissionSettings.enableCheckIn && session.role === 'USER' && session.staff?.roles.some(r => r.groupId === 'g_out' || r.groupId === 'g_service_center');
  const isFullScreen = (activeTab === 'form_designer' && designerMode === 'EDIT') || activeTab === 'interviewee_dashboard';

  const getRoleDisplay = (session: UserSession | null): string => {
    if (!session) return '';
    if (session.role === 'ADMIN') return '超级管理员';
    if (session.staff) {
      if (session.staff.roles.length > 0) {
        const mainRole = session.staff.roles.find(r => r.groupId !== 'g_pending_allocation');
        if (mainRole) return `${mainRole.groupName}${mainRole.isLeader ? '组长' : '组员'}`;
        return '待定岗';
      }
      return '候选人/待定岗';
    }
    return '员工'; 
  };
  const roleDisplayText = getRoleDisplay(session);

  return (
    <div className="flex min-h-screen bg-slate-50 text-gray-900 font-sans">

      {!isFullScreen && (
        <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white transition-transform duration-300 ease-in-out hidden lg:flex flex-col shadow-2xl`}>
          <div className="flex items-center justify-between p-6 border-b border-slate-800">
            <div className="flex items-center gap-3">
              <div className="bg-gradient-to-tr from-blue-500 to-purple-600 p-2 rounded-lg">
                <Layers size={24} className="text-white" />
              </div>
              <div>
                <h1 className="text-xl font-bold tracking-tight">STAFFTool</h1>
                <p className="text-xs text-slate-400">智能人力资源管理</p>
              </div>
            </div>
          </div>

          <nav className="flex-1 overflow-y-auto py-6 px-4 space-y-1 custom-scrollbar">
            {session.role === 'ADMIN' && (
              <>
                 <div className="mb-6">
                    <p className="px-4 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">管理中心</p>
                    <button onClick={() => setActiveTab('dashboard')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'dashboard' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                      <LayoutDashboard size={20} /> <span className="font-medium">工作台</span>
                    </button>
                 </div>
                 <div className="mb-6">
                     <p className="px-4 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">人员管理</p>
                     <button onClick={() => setActiveTab('training_checkin')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'training_checkin' || activeTab === 'registration' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                       <ClipboardCheck size={20} /> <span className="font-medium">报名数据</span>
