                {canScanCheckIn && (
                   <button onClick={() => setActiveTab('checkin_system')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all mt-1 ${activeTab === 'checkin_system' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                     <ScanLine size={20} /> <span className="font-medium">现场签到</span>
