          </nav>

          <div className="p-4 border-t border-slate-800">
             <div className="flex items-center justify-between gap-3 px-2">
               <div className="min-w-0">
                  <p className="text-sm font-bold text-white truncate">{session.staff?.name || '管理员'}</p>
                  <p className="text-xs text-slate-500 truncate">{roleDisplayText}</p>
               </div>
               <button onClick={handleLogout} className="text-slate-500 hover:text-white transition-colors" title="退出登录">
                  <LogOut size={18} />
               </button>
             </div>
          </div>
        </aside>
      )}

      {/* Mobile Sidebar Logic can be updated similarly if needed, currently reusing logic via renderContent state */}
