                     <button onClick={() => setActiveTab('training_checkin')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mb-1 group ${activeTab === 'training_checkin' || activeTab === 'registration' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-white/5 hover:text-white'}`}>
