        </aside>
      )}

      {/* Mobile Sidebar Logic can be updated similarly if needed, currently reusing logic via renderContent state */}
      <main className={`flex-1 flex flex-col min-h-screen transition-all duration-300 ${!isFullScreen ? 'lg:ml-64' : ''}`}>
