                      <button onClick={() => { setActiveTab('training_checkin'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">报名数据</button>
                      <button onClick={() => { setActiveTab('checkin_system'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">现场签到</button>
                      <button onClick={() => { setActiveTab('outsourced'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">分组与编外</button>
                   </>
                 ) : (
                   <>
                      <button onClick={() => { setActiveTab('dashboard'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">我的主页</button>
                      {canScanCheckIn && <button onClick={() => { setActiveTab('checkin_system'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">现场签到</button>}
