                        <div className={`flex items-center gap-1 text-xs font-bold px-2 py-1 rounded-lg shrink-0 ${
                           group.rate >= 90 ? 'bg-green-50 text-green-600' : 
                           group.rate >= 70 ? 'bg-yellow-50 text-yellow-600' : 'bg-red-50 text-red-600'
                        }`}>
                           <TrendingUp size={12} /> {group.rate}%
                        </div>
                     </div>

                     <div>
                        {/* Progress Bar */}
                        <div className="w-full bg-gray-100 h-2.5 rounded-full overflow-hidden mb-3">
                           <div 
                              className={`h-full rounded-full transition-all duration-1000 ${
                                 group.rate >= 90 ? 'bg-green-500' : 
                                 group.rate >= 70 ? 'bg-yellow-500' : 'bg-red-500'
                              }`} 
                              style={{ width: `${group.rate}%` }}
                           ></div>
                        </div>
                        <div className="flex justify-between text-xs font-bold text-gray-400">
                           <span className="flex items-center gap-1"><Users size={12} /> {group.present} / {group.total} 人</span>
                           <span>缺 {group.total - group.present}</span>
                        </div>
                     </div>
                  </div>
               ))
            )}
         </div>
      </div>

      {/* Quick Access Grid (Optional - Shows Key Metrics) */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-8">
         <div className="bg-indigo-50/50 p-5 rounded-3xl border border-indigo-100 flex flex-col items-center justify-center text-center hover:bg-indigo-50 transition-colors cursor-default">
            <h4 className="text-3xl font-black text-indigo-600 mb-1">{staffList.length}</h4>
            <p className="text-xs font-bold text-indigo-400 uppercase tracking-wide">总人数</p>
         </div>
         <div className="bg-emerald-50/50 p-5 rounded-3xl border border-emerald-100 flex flex-col items-center justify-center text-center hover:bg-emerald-50 transition-colors cursor-default">
            <h4 className="text-3xl font-black text-emerald-600 mb-1">{attendanceRecords.length}</h4>
            <p className="text-xs font-bold text-emerald-400 uppercase tracking-wide">今日打卡</p>
         </div>
         <div className="bg-orange-50/50 p-5 rounded-3xl border border-orange-100 flex flex-col items-center justify-center text-center hover:bg-orange-50 transition-colors cursor-default">
            <h4 className="text-3xl font-black text-orange-600 mb-1">{queueData.length}</h4>
            <p className="text-xs font-bold text-orange-400 uppercase tracking-wide">现场签到</p>
         </div>
         <div className="bg-purple-50/50 p-5 rounded-3xl border border-purple-100 flex flex-col items-center justify-center text-center hover:bg-purple-50 transition-colors cursor-default">
            <h4 className="text-3xl font-black text-purple-600 mb-1">{groups.length}</h4>
            <p className="text-xs font-bold text-purple-400 uppercase tracking-wide">活跃分组</p>
         </div>
      </div>

    </div>
  );
};

export default Dashboard;

payload.text:
这是一个非常完整的全栈项目需求。目前的 React 代码结构清晰，逻辑完整，非常适合作为前端蓝本。

为了配合这个前端实现 **Node.js 后端** 并支持 **实时更新 (Real-time)**，我为你梳理了一套完整的后端架构方案。你需要重点关注 **Socket.io** 的集成，因为这是实现“扫码后后台立刻刷新”和“大屏数据实时跳动”的关键。

### 1. 技术栈推荐

*   **运行环境**: Node.js
*   **Web 框架**: Express.js (轻量，上手快) 或 NestJS (更规范，适合大型项目)
*   **数据库**: MongoDB (配合 Mongoose)
    *   *原因*: 你的表单功能 (`FormTemplate`) 是动态结构的，MongoDB 存 JSON 非常方便；且人员数据字段较多，NoSQL 更灵活。
*   **实时通信**: Socket.io
    *   *关键*: 用于解决面试者扫码后，管理员端不需要刷新就能看到签到数据。
*   **图片存储**: Multer (本地存储) 或 阿里云OSS/AWS S3
    *   *注意*: 考勤拍照的 Base64 字符串很大，直接存数据库会拖慢查询，建议转存为文件，数据库只存 URL。

---

### 2. 数据库设计 (MongoDB Schema)

你需要对照前端的 `types.ts` 来建立模型。以下是核心 Schema 定义：

#### A. Staff (员工/人员表)
```javascript
const StaffSchema = new mongoose.Schema({
  name: { type: String, required: true },
  phone: { type: String },
  idCard: { type: String, index: true }, // 设为索引，方便登录查询
  avatar: String,
  status: { type: String, enum: ['PENDING', 'INTERVIEWED', 'ACTIVE', 'REJECTED'] },
  roles: [{
    groupId: { type: mongoose.Schema.Types.ObjectId, ref: 'Group' },
    isLeader: Boolean
  }],
  // ...其他字段
  isTalent: Boolean,
  joinDate: Date
});
```

#### B. Attendance (考勤记录)
```javascript
const AttendanceSchema = new mongoose.Schema({
  staffId: { type: mongoose.Schema.Types.ObjectId, ref: 'Staff', required: true },
  timestamp: { type: Date, default: Date.now },
  type: { type: String, enum: ['IN', 'OUT'] },
  status: { type: String, enum: ['NORMAL', 'LATE', 'EARLY_LEAVE', 'OVERTIME'] },
  photoUrl: String, // 存图片的 URL，不要存 Base64
  location: String
});
```

#### C. QueueTicket (排队/签到表 - 实时核心)
```javascript
const QueueTicketSchema = new mongoose.Schema({
  ticketNumber: String, // A-001
  staffId: { type: mongoose.Schema.Types.ObjectId, ref: 'Staff' },
  status: { type: String, enum: ['WAITING', 'CALLED', 'COMPLETED', 'SKIPPED'], default: 'WAITING' },
  checkInTime: Date,
  calledTime: Date
});
```

---

### 3. 后端核心逻辑与 Socket.io 实时策略

这是你最关心的部分。你需要在一个 Node 服务中同时开启 HTTP API 和 Socket 服务。

#### `server.js` (入口文件示例)

```javascript
const express = require('express');
const http = require('http');
const { Server } = require("socket.io");
const mongoose = require('mongoose');
const cors = require('cors');

const app = express();
app.use(cors());
app.use(express.json({ limit: '50mb' })); // 允许大的 JSON (因为有图片上传)

const server = http.createServer(app);
const io = new Server(server, {
  cors: { origin: "*" } // 允许前端跨域连接
});

// --- Socket.io 逻辑 ---
io.on('connection', (socket) => {
  console.log('Client connected:', socket.id);

  // 1. 管理员/大屏端加入特定房间
  socket.on('join_admin_room', () => {
    socket.join('admin_channel');
  });

  // 2. 候选人个人房间 (用于通知由于 "等待" 变为 "叫号")
  socket.on('join_personal_room', (userId) => {
    socket.join(`user_${userId}`);
  });

  socket.on('disconnect', () => {
    console.log('Client disconnected');
  });
});

// --- API 路由示例 (结合实时推送) ---

// 1. 扫码签到接口
app.post('/api/queue/checkin', async (req, res) => {
  const { staffId } = req.body;

  // ... 数据库保存逻辑 (创建 QueueTicket) ...
  const newTicket = await QueueTicket.create({ staffId, ... });
  const staffInfo = await Staff.findById(staffId);

  // 【关键】: 广播给所有连接的管理员/大屏，告诉他们有人签到了
  io.to('admin_channel').emit('queue_update', {
    action: 'NEW_CHECKIN',
    ticket: newTicket,
    staff: staffInfo
  });

  // 【关键】: 通知候选人本人 (如果他在看手机页面)，"签到成功"
  io.to(`user_${staffId}`).emit('my_status_change', {
    ticket: newTicket
  });

  res.json({ success: true, ticket: newTicket });
});

// 2. 考勤打卡接口
app.post('/api/attendance/clock', async (req, res) => {
  const { staffId, photoBase64, type } = req.body;

  // 1. 将 Base64 转存为文件 (使用 fs 或上传云存储)，拿到 photoUrl
  const photoUrl = await saveImage(photoBase64); 

  // 2. 存入数据库
  const record = await Attendance.create({ staffId, type, photoUrl, ... });

  // 3. 【关键】: 实时推送到 Dashboard
  io.to('admin_channel').emit('attendance_update', {
    record: record
  });

  res.json({ success: true });
});

// 3. 叫号接口
app.post('/api/queue/call', async (req, res) => {
  const { ticketId } = req.body;
  const ticket = await QueueTicket.findByIdAndUpdate(ticketId, { status: 'CALLED' });

  // 通知大屏更新列表
  io.to('admin_channel').emit('queue_update', { action: 'REFRESH' });

  // 【关键】: 手机震动/弹窗通知候选人
  io.to(`user_${ticket.staffId}`).emit('call_notification', {
    message: '轮到您面试了，请前往面试间！'
  });

  res.json({ success: true });
});

server.listen(3000, () => {
  console.log('Server running on port 3000');
});
```

---

### 4. 前端代码调整建议

既然你现在要开始写 Node，前端 `App.tsx` 中大量的 `useEffect` 和 `localStorage` 逻辑就需要逐步替换掉。

1.  **移除 LocalStorage 同步**: `App.tsx` 中的 `window.addEventListener('storage', ...)` 这部分是为了演示用的，对接后端后应完全删除。
2.  **引入 Socket 客户端**:
    在 `App.tsx` 或顶层 Context 中：
    ```typescript
    import { io } from 'socket.io-client';

    // 初始化
    const socket = io('http://localhost:3000');

    useEffect(() => {
      // 监听全局事件
      socket.on('attendance_update', (newRecord) => {
         // 更新 attendanceRecords 状态，Dashboard 数字会自动跳动
         setAttendanceRecords(prev => [newRecord, ...prev]);
      });

      socket.on('queue_update', (data) => {
         // 重新获取队列或直接追加
         // 如果后端传了完整数据，直接 setQueueData
         // 否则 fetchQueueData();
      });

      return () => { socket.off('attendance_update'); socket.off('queue_update'); };
    }, []);
    ```
3.  **图片处理**: 
    `components/Attendance.tsx` 中目前生成的是 `dataUrl` (Base64)。
    *   **保持不变**: 前端依然生成 Base64 用于预览。
    *   **修改 API 调用**: 在 `handleClockAction` 中，将 Base64 发送给后端，或者转换成 `Blob` 使用 `FormData` 上传（推荐后者，传输效率更高）。

---

### 5. 视觉微调 (响应你的“总/服/编”简化需求)

你刚才提到希望去掉 `AllStaffOverview` 和 `OutsourcedManager` 里那些带“总”、“服”字的头像，让界面更清爽。

我这里提供一个小的代码更新，去除这些字母头像，统一使用更现代的图标或纯色块。

