  onShare: () => void;
}

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];
const ITEMS_PER_PAGE = 10;

const FormAnalytics: React.FC<FormAnalyticsProps> = ({ form, submissions, onDeleteSubmission, onBack, onShare }) => {
  const [activeTab, setActiveTab] = useState<'REPORT' | 'INSIGHTS'>('REPORT');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSubmission, setSelectedSubmission] = useState<FormSubmission | null>(null);
  const [currentPage, setCurrentPage] = useState(1);

  // --- Derived Data for Insights ---

  // 1. Daily Submission Stats
  const dailyStats = useMemo(() => {
    const counts: Record<string, number> = {};
    for(let i=6; i>=0; i--) {
        const d = new Date();
        d.setDate(d.getDate() - i);
        const key = d.toLocaleDateString('zh-CN', { month: '2-digit', day: '2-digit' });
        counts[key] = 0;
    }

    submissions.forEach(s => {
      const date = new Date(s.submittedAt).toLocaleDateString('zh-CN', { month: '2-digit', day: '2-digit' });
      if (counts[date] !== undefined) {
          counts[date]++;
      }
    });
    return Object.keys(counts).map(date => ({ name: date, count: counts[date] }));
  }, [submissions]);

  // 2. Analyze Select Fields
  const selectFieldStats = useMemo(() => {
    return form.fields
      .filter(f => f.type === 'SELECT' || f.type === 'GENDER')
      .map(field => {
        const counts: Record<string, number> = {};
        submissions.forEach(s => {
          const val = s.data[field.id] || '未填';
          counts[val] = (counts[val] || 0) + 1;
        });
        const data = Object.keys(counts).map(k => ({ name: k, value: counts[k] }));
        return { fieldName: field.label, data };
      });
  }, [form, submissions]);

  // --- Derived Data for Report ---

  // Smart Column Detection
  const summaryFields = useMemo(() => {
    const priorityFields = form.fields.filter(f => 
        f.label.includes('姓名') || f.label.toLowerCase().includes('name') ||
        f.type === 'GENDER' || f.label.includes('性别') ||
        f.type === 'PHONE' || f.label.includes('手机') ||
        f.type === 'ID_CARD'
    );

    // Fallback: If no priority fields found, take first 4 fields
    if (priorityFields.length === 0) {
        return form.fields.slice(0, 4);
    }

    return priorityFields.slice(0, 5);
  }, [form.fields]);

  const filteredSubmissions = useMemo(() => {
    return submissions.filter(s => {
       const searchLower = searchTerm.toLowerCase();
       return Object.values(s.data).some(val => 
         String(val).toLowerCase().includes(searchLower)
       );
    }).sort((a, b) => new Date(b.submittedAt).getTime() - new Date(a.submittedAt).getTime());
  }, [submissions, searchTerm]);

  // Pagination Logic
  const totalPages = Math.ceil(filteredSubmissions.length / ITEMS_PER_PAGE);
  const paginatedSubmissions = useMemo(() => {
      const start = (currentPage - 1) * ITEMS_PER_PAGE;
      return filteredSubmissions.slice(start, start + ITEMS_PER_PAGE);
  }, [filteredSubmissions, currentPage]);

  const handleExport = () => {
    const headers = ['提交时间', ...form.fields.map(f => f.label)].join(',');
    const rows = filteredSubmissions.map(s => {
        const date = new Date(s.submittedAt).toLocaleString('zh-CN');
        const values = form.fields.map(f => {
            let val = s.data[f.id] || '';
            if (typeof val === 'object') val = JSON.stringify(val);
            if (String(val).includes(',') || String(val).includes('"') || String(val).includes('\n')) {
                return `"${String(val).replace(/"/g, '""')}"`;
            }
            return val;
        });
        return [date, ...values].join(',');
    });

    const csvContent = "\ufeff" + [headers, ...rows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `${form.title}_数据报表.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleDelete = (id: string) => {
    if (confirm('确定要删除这条提交记录吗？此操作无法撤销。')) {
      if (onDeleteSubmission) onDeleteSubmission(id);
      if (selectedSubmission?.id === id) setSelectedSubmission(null);
    }
  };

  const handleClearAll = () => {
    if (submissions.length === 0) return;
    if (confirm(`⚠️ 警告：确定要清空所有 ${submissions.length} 条数据吗？\n\n此操作不可恢复！建议先导出备份。`)) {
       // Loop delete or use a clear method if available in parent. 
       // Currently App.tsx only supports single delete via `onDeleteSubmission`, 
       // but we can iterate since we are in memory (for demo) or if backend supports it.
       // Here we iterate for safety with the current props interface.
       if (onDeleteSubmission) {
          submissions.forEach(s => onDeleteSubmission(s.id));
       }
    }
  };

  const getFieldValueDisplay = (val: any) => {
      if (val === undefined || val === null || val === '') return '-';
      if (typeof val === 'object') {
          return Object.keys(val).length > 0 ? `已选 ${Object.keys(val).length} 项` : '-';
      }
      return String(val);
  };

  return (
    <div className="flex flex-col h-full bg-gray-50/50">

      {/* 1. Header */}
      <div className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-20">
         <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-lg text-gray-500 transition-colors">
               <ArrowLeft size={20} />
            </button>
            <div>
               <h1 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                 {form.title} <span className="text-gray-400 font-normal text-sm px-2 bg-gray-100 rounded-full">共 {submissions.length} 条</span>
               </h1>
            </div>
         </div>
         <div className="flex gap-2">
            <button 
               onClick={onShare}
               className="px-4 py-2 border border-gray-200 text-gray-600 rounded-lg text-sm font-bold hover:bg-gray-50 transition-colors flex items-center gap-2"
            >
               <Share2 size={16} /> 分享链接
            </button>
            {submissions.length > 0 && onDeleteSubmission && (
               <button 
                  onClick={handleClearAll}
                  className="px-4 py-2 bg-white border border-red-200 text-red-600 rounded-lg text-sm font-bold hover:bg-red-50 transition-colors flex items-center gap-2"
               >
                  <RotateCcw size={16} /> 清空数据
               </button>
            )}
            <button 
               onClick={handleExport}
               className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-sm"
            >
               <Download size={16} /> 导出 Excel
            </button>
         </div>
      </div>

      {/* 2. Tabs */}
      <div className="bg-white border-b border-gray-200 px-6">
         <div className="flex gap-6">
            <button 
              onClick={() => setActiveTab('REPORT')}
              className={`py-3 text-sm font-bold border-b-2 transition-colors flex items-center gap-2 ${activeTab === 'REPORT' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500 hover:text-gray-800'}`}
            >
               <Table size={16} /> 数据明细
            </button>
            <button 
              onClick={() => setActiveTab('INSIGHTS')}
              className={`py-3 text-sm font-bold border-b-2 transition-colors flex items-center gap-2 ${activeTab === 'INSIGHTS' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500 hover:text-gray-800'}`}
            >
               <TrendingUp size={16} /> 统计分析
            </button>
         </div>
      </div>

      {/* 3. Content */}
      <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">

         {/* --- REPORT TAB --- */}
         {activeTab === 'REPORT' && (
            <div className="max-w-6xl mx-auto space-y-4">
               {/* Search Bar */}
               <div className="bg-white p-2 rounded-xl shadow-sm border border-gray-200 flex items-center gap-2 w-full md:w-96">
                  <Search size={18} className="text-gray-400 ml-2" />
                  <input 
                    type="text" 
                    value={searchTerm}
                    onChange={(e) => { setSearchTerm(e.target.value); setCurrentPage(1); }}
                    placeholder="搜索关键词..."
                    className="flex-1 outline-none text-sm p-1"
                  />
                  {searchTerm && <button onClick={() => setSearchTerm('')}><X size={14} className="text-gray-400 mr-2" /></button>}
               </div>

               {/* Data Table */}
               <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                  <div className="overflow-x-auto">
                     <table className="w-full text-left">
                        <thead className="bg-gray-50 border-b border-gray-200 text-gray-500 text-xs uppercase font-bold">
                           <tr>
                              <th className="p-4 whitespace-nowrap w-20">#</th>
                              <th className="p-4 whitespace-nowrap">提交时间</th>
                              {summaryFields.map(f => (
                                 <th key={f.id} className="p-4 whitespace-nowrap">{f.label}</th>
                              ))}
                              <th className="p-4 whitespace-nowrap text-right">操作</th>
                           </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                           {paginatedSubmissions.length === 0 ? (
                              <tr>
                                 <td colSpan={summaryFields.length + 3} className="p-12 text-center text-gray-400">
                                    <FileSpreadsheet size={48} className="mx-auto mb-4 opacity-20" />
                                    <p>没有找到相关数据</p>
                                 </td>
                              </tr>
                           ) : (
                              paginatedSubmissions.map((sub, idx) => (
                                 <tr key={sub.id} className="hover:bg-gray-50 transition-colors group">
                                    <td className="p-4 text-gray-400 font-mono text-xs">
                                       {(currentPage - 1) * ITEMS_PER_PAGE + idx + 1}
                                    </td>
                                    <td className="p-4 text-sm text-gray-600 whitespace-nowrap">
                                       {new Date(sub.submittedAt).toLocaleString('zh-CN')}
                                    </td>
                                    {summaryFields.map(f => (
                                       <td key={f.id} className="p-4 text-sm text-gray-800 max-w-[200px] truncate">
                                          {getFieldValueDisplay(sub.data[f.id])}
                                       </td>
                                    ))}
                                    <td className="p-4 text-right">
                                       <div className="flex items-center justify-end gap-2">
                                          <button 
                                             onClick={() => setSelectedSubmission(sub)}
                                             className="p-1.5 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                                             title="查看详情"
                                          >
                                             <Eye size={16} />
                                          </button>
                                          {onDeleteSubmission && (
                                             <button 
                                                onClick={() => handleDelete(sub.id)}
                                                className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                                title="删除记录"
                                             >
                                                <Trash2 size={16} />
                                             </button>
                                          )}
                                       </div>
                                    </td>
                                 </tr>
                              ))
                           )}
                        </tbody>
                     </table>
                  </div>

                  {/* Pagination */}
                  {totalPages > 1 && (
                     <div className="p-4 border-t border-gray-200 flex justify-between items-center bg-gray-50">
                        <span className="text-xs text-gray-500">
                           显示 {(currentPage - 1) * ITEMS_PER_PAGE + 1} - {Math.min(currentPage * ITEMS_PER_PAGE, filteredSubmissions.length)} 条，共 {filteredSubmissions.length} 条
                        </span>
                        <div className="flex gap-2">
                           <button 
                              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                              disabled={currentPage === 1}
                              className="p-1.5 rounded-lg border border-gray-300 bg-white disabled:opacity-50 hover:bg-gray-100"
                           >
                              <ChevronLeft size={16} />
                           </button>
                           <span className="text-sm font-bold flex items-center px-2">{currentPage} / {totalPages}</span>
                           <button 
                              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                              disabled={currentPage === totalPages}
                              className="p-1.5 rounded-lg border border-gray-300 bg-white disabled:opacity-50 hover:bg-gray-100"
                           >
                              <ChevronRight size={16} />
                           </button>
                        </div>
                     </div>
                  )}
               </div>
            </div>
         )}

         {/* --- INSIGHTS TAB --- */}
         {activeTab === 'INSIGHTS' && (
            <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-6 pb-20">

               {/* 1. Daily Trend */}
               <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 md:col-span-2">
                  <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
                     <BarChart size={18} className="text-indigo-600" /> 近7天提交趋势
                  </h3>
                  <div className="h-64 w-full">
                     <ResponsiveContainer width="100%" height="100%">
                        <ReChart data={dailyStats}>
                           <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                           <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#9ca3af'}} />
                           <YAxis axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#9ca3af'}} allowDecimals={false} />
                           <Tooltip cursor={{fill: '#f3f4f6'}} contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)'}} />
                           <Bar dataKey="count" fill="#6366f1" radius={[4, 4, 0, 0]} barSize={30} />
                        </ReChart>
                     </ResponsiveContainer>
                  </div>
               </div>

               {/* 2. Field Analysis (Pie Charts for Selects) */}
               {selectFieldStats.map((stat, idx) => (
                  <div key={idx} className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                     <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
                        <PieIcon size={18} className="text-pink-500" /> {stat.fieldName} 分布
                     </h3>
                     <div className="h-64 w-full flex items-center justify-center">
                        {stat.data.length > 0 ? (
                           <ResponsiveContainer width="100%" height="100%">
                              <PieChart>
                                 <Pie
                                    data={stat.data}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={60}
                                    outerRadius={80}
                                    paddingAngle={5}
                                    dataKey="value"
                                 >
                                    {stat.data.map((entry, index) => (
                                       <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                    ))}
                                 </Pie>
                                 <Tooltip />
                                 <Legend verticalAlign="bottom" height={36} />
                              </PieChart>
                           </ResponsiveContainer>
                        ) : (
                           <p className="text-gray-400 text-sm">暂无数据</p>
                        )}
                     </div>
                  </div>
               ))}

               {selectFieldStats.length === 0 && (
                  <div className="col-span-full py-12 text-center text-gray-400 border border-dashed rounded-xl">
                     没有可统计的选项类题目 (如下拉选择、性别等)
                  </div>
               )}
            </div>
         )}
      </div>

      {/* Details Modal */}
      {selectedSubmission && (
         <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setSelectedSubmission(null)}>
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg max-h-[80vh] flex flex-col overflow-hidden animate-in zoom-in duration-200" onClick={e => e.stopPropagation()}>
               <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                  <div className="flex items-center gap-2">
                     <FileText size={18} className="text-indigo-600" />
                     <h3 className="font-bold text-lg text-gray-800">提交详情</h3>
                  </div>
                  <button onClick={() => setSelectedSubmission(null)} className="text-gray-400 hover:text-gray-600"><X size={20} /></button>
               </div>

               <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
                  <div className="flex items-center gap-2 text-xs text-gray-400 mb-4 bg-gray-50 p-2 rounded-lg border border-gray-100">
                     <Clock size={12} /> 提交时间：{new Date(selectedSubmission.submittedAt).toLocaleString()}
                  </div>

                  {form.fields.map(field => {
                     const val = selectedSubmission.data[field.id];
                     return (
                        <div key={field.id} className="border-b border-gray-50 pb-3 last:border-0">
                           <p className="text-xs font-bold text-gray-500 uppercase mb-1">{field.label}</p>
                           <div className="text-sm text-gray-800 font-medium break-words">
                              {field.type === 'SIGNATURE' && val ? (
                                 <img src={val} alt="Signature" className="h-16 border border-gray-200 rounded p-1" />
                              ) : (
                                 getFieldValueDisplay(val)
                              )}
                           </div>
                        </div>
                     );
                  })}
               </div>

               <div className="p-4 border-t border-gray-100 bg-gray-50 flex justify-end gap-2">
                  <button onClick={() => setSelectedSubmission(null)} className="px-4 py-2 bg-white border border-gray-200 rounded-lg text-gray-700 hover:bg-gray-100 text-sm font-bold">关闭</button>
                  {onDeleteSubmission && (
                     <button 
                        onClick={() => handleDelete(selectedSubmission.id)}
                        className="px-4 py-2 bg-red-50 text-red-600 border border-red-100 rounded-lg text-sm font-bold hover:bg-red-100 flex items-center gap-2"
                     >
                        <Trash2 size={14} /> 删除记录
                     </button>
                  )}
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

export default FormAnalytics;

