import React, { useState, useEffect } from 'react';
import { User, Lock, ArrowRight, Smartphone, CreditCard, AlertCircle, Check, Zap, Briefcase, ShieldCheck, UserPlus } from 'lucide-react';
import { AdminUser, Staff, LoginConfig, RegistrationRecord } from '../types';

interface LoginProps {
  staffList: Staff[];
  registrationList: RegistrationRecord[];
  onSiteRecords?: RegistrationRecord[]; // Added optional prop
  onLogin: (userId: string, role: 'ADMIN' | 'USER') => void;
  adminUsers: AdminUser[];
  loginConfig?: LoginConfig;
}

type LoginMode = 'STAFF' | 'CANDIDATE' | 'ADMIN';

const Login: React.FC<LoginProps> = ({ staffList, registrationList, onSiteRecords = [], onLogin, adminUsers, loginConfig }) => {
  // Login Mode State
  const [loginMode, setLoginMode] = useState<LoginMode>('STAFF');

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    idCardSuffix: '', // Last 6 digits
    adminUser: '',
    adminPass: '',
    captchaInput: ''
  });

  const [captchaCode, setCaptchaCode] = useState('');
  const [countdown, setCountdown] = useState(60); 
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Status Feedback View
  const [loginStatusView, setLoginStatusView] = useState<'NORMAL' | 'REJECTED' | 'WAITING_GROUP'>('NORMAL');

  // Generate Captcha
  const generateCaptcha = () => {
    const chars = '23456789ABCDEFGHJKLMNPQRSTUVWXYZ';
    let result = '';
    for (let i = 0; i < 4; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    setCaptchaCode(result);
    setCountdown(60); 
  };

  // Initial Captcha & Auto Refresh Timer (60s)
  useEffect(() => {
    generateCaptcha();
    const interval = setInterval(() => generateCaptcha(), 60000);
    const countdownInterval = setInterval(() => {
      setCountdown((prev) => (prev > 0 ? prev - 1 : 60));
    }, 1000);

    return () => {
      clearInterval(interval);
      clearInterval(countdownInterval);
    };
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    setLoading(true);
    setTimeout(() => {
        setLoading(false);
        processLogin();
    }, 500);
  };

  const processLogin = () => {
    setLoginStatusView('NORMAL');

    // --- ADMIN LOGIN ---
    if (loginMode === 'ADMIN') {
      if (formData.captchaInput.toUpperCase() !== captchaCode) {
         setError('验证码错误');
         generateCaptcha();
         setFormData({...formData, captchaInput: ''});
         return;
      }
      const admin = adminUsers.find(u => u.username === formData.adminUser && u.password === formData.adminPass);
      if (admin) {
        onLogin(admin.username, 'ADMIN');
      } else {
        setError('账号或密码错误');
        generateCaptcha();
      }
      return;
    }

    // --- USER LOGIN (STAFF OR CANDIDATE) ---
    const { name, phone, idCardSuffix } = formData;
    if (!name || !phone || !idCardSuffix) {
       setError('请补全信息');
       return;
    }

    // 1. STAFF MODE: Search only in Staff List (Official Employees)
    if (loginMode === 'STAFF') {
      const staff = staffList.find(s => s.name === name && s.phone === phone);

      if (staff) {
        const actualIdSuffix = staff.idCard ? staff.idCard.slice(-6) : '';
        if (actualIdSuffix !== idCardSuffix) {
           setError('身份校验失败，请检查身份证后6位');
           return;
        }

        if (staff.status === 'REJECTED') {
          setLoginStatusView('REJECTED');
          return;
        }

        onLogin(staff.id, 'USER');
        return;
      } else {
        setError('未找到该员工，请确认您已入职或切换到“面试/报名”入口');
        return;
      }
    }

    // 2. CANDIDATE MODE: Search in Registration List & OnSite Records
    if (loginMode === 'CANDIDATE') {
      // Combine lists for search
      const allCandidates = [...registrationList, ...onSiteRecords];
      const candidate = allCandidates.find(r => r.name === name && r.phone === phone);

      if (candidate) {
          const actualIdSuffix = candidate.idCard ? candidate.idCard.slice(-6) : '';
          // Only validate suffix if ID card exists in record
          if (candidate.idCard && actualIdSuffix !== idCardSuffix) {
              setError('身份校验失败，请检查身份证后6位');
              return;
          }
          // Allow candidates to login -> they will see IntervieweeDashboard
          onLogin(candidate.id, 'USER');
          return;
      } else {
        setError('未找到报名信息，请检查输入或联系管理员');
        return;
      }
    }

    setError('未知登录错误');
  };

  const resetForm = () => {
    setLoginStatusView('NORMAL');
    setFormData({ name: '', phone: '', idCardSuffix: '', adminUser: '', adminPass: '', captchaInput: '' });
    generateCaptcha();
    setError('');
  };

  // --- Feedback Screens ---
  if (loginStatusView === 'REJECTED') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 font-sans p-4">
        <div className="bg-white p-8 rounded-3xl shadow-lg w-full max-w-xs border border-gray-100 animate-in zoom-in duration-300">
