                      type="tel" 
                      placeholder="手机号"
                      value={formData.phone}
                      onChange={e => setFormData({...formData, phone: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-sm font-medium placeholder-gray-400"
                    />
                 </div>
                 <div className="relative group">
                    <CreditCard size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors" />
                    <input 
                      type="text" 
                      maxLength={6}
                      placeholder="身份证后6位"
                      value={formData.idCardSuffix}
                      onChange={e => setFormData({...formData, idCardSuffix: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-sm font-medium placeholder-gray-400"
                    />
                 </div>
              </div>
            ) : (
              <div className="space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
                 <div className="relative group">
                    <User size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-gray-800 transition-colors" />
                    <input 
                      type="text" 
                      placeholder="管理员账号"
                      value={formData.adminUser}
                      onChange={e => setFormData({...formData, adminUser: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-gray-300 focus:ring-0 outline-none transition-all text-sm font-medium"
                    />
                 </div>
                 <div className="relative group">
                    <Lock size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-gray-800 transition-colors" />
                    <input 
                      type="password" 
                      placeholder="密码"
                      value={formData.adminPass}
                      onChange={e => setFormData({...formData, adminPass: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-gray-300 focus:ring-0 outline-none transition-all text-sm font-medium"
                    />
                 </div>
                 <div className="flex gap-2">
                    <input
                       type="text"
                       maxLength={4}
                       placeholder="验证码"
                       value={formData.captchaInput}
                       onChange={e => setFormData({...formData, captchaInput: e.target.value})}
                       className="flex-1 px-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-gray-300 outline-none transition-all text-sm font-medium text-center uppercase"
                    />
                    <div 
                      onClick={generateCaptcha}
                      className="w-28 bg-gray-100 rounded-2xl flex flex-col items-center justify-center cursor-pointer relative overflow-hidden group hover:bg-gray-200 transition-colors border border-transparent"
                    >
                        <span className="font-mono font-bold text-gray-600 text-lg tracking-widest z-10">{captchaCode}</span>
                        <div className="absolute bottom-0 left-0 h-1 bg-indigo-400 transition-all duration-1000 ease-linear opacity-50" style={{ width: `${(countdown/60)*100}%` }}></div>
                    </div>
                 </div>
              </div>
            )}

            {error && (
               <div className="bg-red-50 text-red-500 text-xs flex items-center justify-center gap-1.5 py-2.5 rounded-xl border border-red-100 animate-pulse font-medium">
                  <AlertCircle size={14} /> {error}
               </div>
            )}

            <button
               type="submit"
               disabled={loading}
               className={`w-full py-4 rounded-2xl font-bold text-base text-white shadow-xl flex items-center justify-center gap-2 transform active:scale-95 transition-all
                 ${loginMode === 'ADMIN' 
                   ? 'bg-gray-900 hover:bg-black shadow-gray-200' 
                   : loginMode === 'CANDIDATE' 
                     ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'
                     : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'}
               `}
            >
               {loading ? '处理中...' : (
                 <>
                   {loginMode === 'ADMIN' ? '进入后台' : loginMode === 'CANDIDATE' ? '进入面试/等待区' : '员工登录'} <ArrowRight size={18} />
                 </>
               )}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

