  ScanLine
} from 'lucide-react';

// Mock Data (minimal for init)
const MOCK_ADMIN: AdminUser = { username: 'admin', password: '123' };
const INITIAL_CONFIG: AttendanceConfig = { startTime: '09:00', endTime: '18:00', overtimeStart: '19:00' };
const INITIAL_PERMISSIONS: PermissionSettings = {
  allowLeaderExport: true,
  allowLeaderBroadcast: true,
  allowStaffViewTeam: false,
  showSensitiveInfo: true,
  enableCheckIn: true
};
const INITIAL_LOGIN_CONFIG: LoginConfig = { title: 'STAFF System', subtitle: 'Management Portal', imageUrl: '' };
const INITIAL_REG_CONFIG: RegistrationConfig = { masterPrefix: 'M', onSitePrefix: 'S' };

const App: React.FC = () => {
  // --- Global State ---
  const [session, setSession] = useState<UserSession | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');

  // Data State
  const [staffList, setStaffList] = useState<Staff[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [registrationList, setRegistrationList] = useState<RegistrationRecord[]>([]);
  const [onSiteRecords, setOnSiteRecords] = useState<RegistrationRecord[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [queue, setQueue] = useState<QueueTicket[]>([]);
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [forms, setForms] = useState<FormTemplate[]>([]);
  const [formSubmissions, setFormSubmissions] = useState<FormSubmission[]>([]);
  const [scheduleData, setScheduleData] = useState<ScheduleData>({ headers: [], dynamicHeaders: [], rows: [] });
  const [interviewSessions, setInterviewSessions] = useState<InterviewSession[]>([]);

  // Config State
  const [adminUsers, setAdminUsers] = useState<AdminUser[]>([MOCK_ADMIN]);
  const [attendanceConfig, setAttendanceConfig] = useState<AttendanceConfig>(INITIAL_CONFIG);
  const [permissionSettings, setPermissionSettings] = useState<PermissionSettings>(INITIAL_PERMISSIONS);
  const [loginConfig, setLoginConfig] = useState<LoginConfig>(INITIAL_LOGIN_CONFIG);
  const [registrationConfig, setRegistrationConfig] = useState<RegistrationConfig>(INITIAL_REG_CONFIG);
  const [domain, setDomain] = useState('http://localhost:3000');

  // UI State for Forms
  const [selectedFormId, setSelectedFormId] = useState<string | null>(null);
  const [formMode, setFormMode] = useState<'EDIT' | 'ANALYTICS' | 'PREVIEW' | 'SIMULATE'>('EDIT');
  const [designerMode, setDesignerMode] = useState<'EDIT' | 'PREVIEW'>('EDIT');

  // UI State for Mobile Sidebar
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // --- Handlers ---

  const handleLogin = (userId: string, role: 'ADMIN' | 'USER') => {
    if (role === 'ADMIN') {
      setSession({ userId, role });
      setActiveTab('dashboard');
    } else {
      const staff = staffList.find(s => s.id === userId);
      // Check if it's a candidate login (from registration list)
      if (!staff) {
         const candidate = [...registrationList, ...onSiteRecords].find(r => r.id === userId);
         if (candidate) {
            // Temporary staff object for candidate view
            const tempStaff: Staff = {
               id: candidate.id,
               name: candidate.name,
               idCard: candidate.idCard || '',
               avatar: '',
               status: 'PENDING', // Or INTERVIEWED
               roles: [],
               joinDate: new Date().toISOString(),
               registrationNumber: candidate.registrationNumber
            };
            setSession({ userId, role: 'USER', staff: tempStaff });
         } else {
            alert('User not found');
         }
      } else {
         setSession({ userId, role: 'USER', staff });
      }
    }
  };

  const handleLogout = () => {
    setSession(null);
    setActiveTab('dashboard');
    setIsSidebarOpen(false);
  };

  // --- Render Logic ---

  // 1. Public Form Simulation (No session needed)
  if (activeTab === 'public_view_simulation' && selectedFormId) {
     const form = forms.find(f => f.id === selectedFormId);
     if (form) return <PublicDynamicForm form={form} onSubmit={(sub) => setFormSubmissions([...formSubmissions, sub])} onCancel={() => { if (session) { if (designerMode === 'PREVIEW') setActiveTab('form_designer'); else setActiveTab('form_manager'); } else setActiveTab('login'); }} />;
  }

  // 2. Login Screen
  if (!session) {
    return <Login 
      staffList={staffList} 
      registrationList={registrationList} 
      onSiteRecords={onSiteRecords} 
      onLogin={handleLogin} 
      adminUsers={adminUsers} 
      loginConfig={loginConfig} 
    />;
  }

  // 3. User Dashboard (Staff / Candidate)
  if (session.role === 'USER' && session.staff) {
    // If candidate (status PENDING or INTERVIEWED with no roles?) - Basic check
    // Actually StaffDashboard handles attendance. IntervieweeDashboard handles queuing.
    // Let's decide based on status.
    const isCandidate = session.staff.status === 'PENDING' || session.staff.status === 'INTERVIEWED' || session.staff.status === 'REJECTED'; // Or check if in staffList vs registrationList

    // Check if truly in staff list as active employee
    const isEmployee = staffList.some(s => s.id === session.staff?.id && s.status === 'ACTIVE');

    if (!isEmployee) {
       // Find ticket
       const myTicket = queue.find(t => t.staffId === session.userId);
       // Calc tickets ahead
       const myIndex = queue.findIndex(t => t.staffId === session.userId);
       const ticketsAhead = myIndex > -1 ? queue.slice(0, myIndex).filter(t => t.status === 'WAITING').length : 0;

       return <IntervieweeDashboard 
          staff={session.staff}
          myTicket={myTicket}
          ticketsAhead={ticketsAhead}
          onLogout={handleLogout}
       />;
    }

    // Is Employee
    const staffGroupRole = session.staff.roles[0]; // Simplification
    const group = groups.find(g => g.id === staffGroupRole?.groupId);
    const leaders = staffList.filter(s => s.roles.some(r => r.groupId === group?.id && r.isLeader));

    // Get today's attendance
    const today = new Date().toISOString().split('T')[0];
    const todayRecords = attendanceRecords.filter(r => r.staffId === session.userId && r.timestamp.startsWith(today));

    // Determine status
    let status: 'CLOCKED_IN' | 'CLOCKED_OUT' = 'CLOCKED_OUT';
    if (todayRecords.length > 0) {
       const last = todayRecords.sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())[0];
       if (last.type === 'IN') status = 'CLOCKED_IN';
    }

    return <StaffDashboard 
      currentUser={session.staff}
      group={group}
      leaders={leaders}
      staffList={staffList}
      announcements={announcements}
      attendanceStatus={status}
      attendanceHistory={todayRecords}
      attendanceConfig={attendanceConfig}
      onClockIn={(url, s, t) => setAttendanceRecords([...attendanceRecords, {id: crypto.randomUUID(), staffId: session.userId, timestamp: t, type: 'IN', photoUrl: url, status: s}])}
      onClockOut={(url, s, t) => setAttendanceRecords([...attendanceRecords, {id: crypto.randomUUID(), staffId: session.userId, timestamp: t, type: 'OUT', photoUrl: url, status: s}])}
    />;
  }

  // 4. Admin Dashboard Layout
  const NavItem = ({ id, label, icon: Icon }: any) => (
    <button
      onClick={() => { setActiveTab(id); setIsSidebarOpen(false); }}
      className={`flex items-center gap-3 w-full px-4 py-3 text-sm font-medium transition-colors rounded-xl ${
        activeTab === id ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:bg-gray-100'
      }`}
    >
      <Icon size={18} />
      <span>{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen bg-gray-50 flex font-sans text-gray-800">

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/50 z-40 md:hidden" onClick={() => setIsSidebarOpen(false)} />
      )}

      {/* Sidebar */}
      <aside className={`fixed md:sticky top-0 h-screen w-64 bg-white border-r border-gray-200 z-50 transform transition-transform duration-200 ease-in-out md:transform-none flex flex-col ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
         <div className="p-6 border-b border-gray-100 flex justify-between items-center">
            <h1 className="text-2xl font-black text-indigo-600 tracking-tight flex items-center gap-2">
               <Briefcase className="fill-indigo-600 text-white" />
               Manager
            </h1>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden text-gray-400">
               <X size={20} />
            </button>
         </div>

         <nav className="flex-1 overflow-y-auto p-4 space-y-1 custom-scrollbar">
            <div className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 px-4 mt-2">概览</div>
            <NavItem id="dashboard" label="仪表盘" icon={LayoutDashboard} />

            <div className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 px-4 mt-6">人员管理</div>
            <NavItem id="staff_active" label="正式员工/架构" icon={Users} />
            <NavItem id="outsourced" label="编外人员管理" icon={Users} />
            <NavItem id="talent_pool" label="企业人才库" icon={Award} />

            <div className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 px-4 mt-6">招聘与考勤</div>
            <NavItem id="recruitment" label="面试/候选人" icon={Users} />
            <NavItem id="training_checkin" label="培训/活动签到" icon={ScanLine} />
            <NavItem id="checkin_terminal" label="核销终端" icon={ScanLine} />
            <NavItem id="attendance_report" label="考勤报表" icon={Calendar} />
            <NavItem id="schedule" label="排班管理" icon={Calendar} />

            <div className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 px-4 mt-6">工具</div>
            <NavItem id="form_manager" label="表单中心" icon={FileText} />
            <NavItem id="announcements" label="公告通知" icon={MessageSquare} />
            <NavItem id="interview_ai" label="AI 面试助手" icon={MessageSquare} />

            <div className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 px-4 mt-6">系统</div>
            <NavItem id="settings" label="系统设置" icon={Settings} />
         </nav>

         <div className="p-4 border-t border-gray-100">
            <button onClick={handleLogout} className="flex items-center gap-2 text-gray-500 hover:text-red-600 w-full px-4 py-2 rounded-lg transition-colors text-sm font-medium">
               <LogOut size={18} /> 退出登录
            </button>
         </div>
