               <Menu size={20} />
            </button>
            <span className="font-bold text-gray-800">管理后台</span>
            <div className="w-9" /> {/* Spacer */}
         </div>

         <div className="p-4 md:p-8 max-w-[1600px] mx-auto">
            {activeTab === 'dashboard' && <Dashboard 
               attendanceRecords={attendanceRecords}
               queueData={queue}
               announcements={announcements}
               isAdmin={true}
               staffList={staffList}
               groups={groups}
               currentUser={undefined} // Admin doesn't strictly need a staff profile here
            />}

            {activeTab === 'staff_active' && <StaffManager 
               viewMode="EMPLOYEES"
               staffList={staffList}
               groups={groups}
               onUpdateStaff={(s) => setStaffList(staffList.map(item => item.id === s.id ? s : item))}
               onAddStaff={(s) => setStaffList([...staffList, s])}
               onBatchAddStaff={(list) => setStaffList([...staffList, ...list])}
               onAddGroup={(g) => setGroups([...groups, g])}
               onDeleteGroup={(id) => setGroups(groups.filter(g => g.id !== id))}
            />}

            {activeTab === 'outsourced' && <OutsourcedManager 
               staffList={staffList}
               groups={groups}
               registrationList={registrationList}
               onSiteRecords={onSiteRecords}
               permissionSettings={permissionSettings}
               onUpdateStaff={(s) => setStaffList(staffList.map(item => item.id === s.id ? s : item))}
               onAddStaff={(s) => setStaffList([...staffList, s])}
               onBatchAddStaff={(list) => setStaffList([...staffList, ...list])}
               onAddGroup={(g) => setGroups([...groups, g])}
               onUpdateGroup={(g) => setGroups(groups.map(item => item.id === g.id ? g : item))}
               onDeleteGroup={(id) => setGroups(groups.filter(g => g.id !== id))}
            />}

            {activeTab === 'recruitment' && <StaffManager 
               viewMode="CANDIDATES"
               staffList={staffList} // In this app, candidates are also stored in staffList with PENDING status
               groups={groups}
               onUpdateStaff={(s) => setStaffList(staffList.map(item => item.id === s.id ? s : item))}
               onAddStaff={(s) => setStaffList([...staffList, s])}
               onBatchAddStaff={(list) => setStaffList([...staffList, ...list])}
               onAddGroup={() => {}}
               onDeleteGroup={() => {}}
            />}

            {activeTab === 'talent_pool' && <TalentPool 
               staffList={staffList}
               registrationList={registrationList}
               onUpdateStaff={(s) => setStaffList(staffList.map(item => item.id === s.id ? s : item))}
               onUpdateRegistration={(list) => setRegistrationList(list)}
            />}

            {activeTab === 'attendance_report' && <AttendanceReports 
               staffList={staffList}
               groups={groups}
               allRecords={attendanceRecords}
               session={session}
               permissionSettings={permissionSettings}
               attendanceConfig={attendanceConfig}
               onUpdateOrAddRecord={(sid, date, type, time) => {
                  // Complex logic to upsert record
                  const ts = `${date}T${time}:00`;
                  // Simplified: Append new record
                  setAttendanceRecords([...attendanceRecords, {id: crypto.randomUUID(), staffId: sid, type, timestamp: ts, status: 'NORMAL', isManual: true}]);
               }}
            />}

            {activeTab === 'schedule' && <StaffScheduleManager 
               scheduleData={scheduleData}
               onUpdateData={setScheduleData}
            />}

            {activeTab === 'announcements' && <AnnouncementManager 
               currentUserRole="ADMIN"
               currentUserGroups={[]}
               announcements={announcements}
               onAddAnnouncement={(a) => setAnnouncements([...announcements, a])}
               onDeleteAnnouncement={(id) => setAnnouncements(announcements.filter(a => a.id !== id))}
               currentUserName="Administrator"
            />}

            {activeTab === 'interview_ai' && <Interview 
               onSaveSession={(s) => setInterviewSessions([...interviewSessions, s])}
            />}

            {activeTab === 'form_manager' && <FormManager 
               forms={forms}
               onCreateForm={() => {
                  const newForm: FormTemplate = {
                     id: crypto.randomUUID(),
                     shareToken: Math.random().toString(36).substring(7),
                     title: '新表单',
                     description: '',
                     status: 'DRAFT',
                     createdDate: new Date().toISOString().split('T')[0],
                     fields: [],
                     submissionCount: 0,
                     themeColor: 'blue'
                  };
                  setForms([...forms, newForm]);
                  setSelectedFormId(newForm.id);
                  setActiveTab('form_designer');
               }}
               onSelectForm={(id, action) => {
                  setSelectedFormId(id);
                  if (action === 'EDIT') setActiveTab('form_designer');
                  else if (action === 'ANALYTICS') setActiveTab('form_analytics');
                  else if (action === 'PREVIEW') setActiveTab('form_share');
               }}
               onDeleteForm={(id) => setForms(forms.filter(f => f.id !== id))}
               onToggleStatus={(id, status) => setForms(forms.map(f => f.id === id ? { ...f, status } : f))}
            />}

            {activeTab === 'form_designer' && selectedFormId && (
               <FormDesigner 
                  form={forms.find(f => f.id === selectedFormId)!}
                  onSave={(updated) => setForms(forms.map(f => f.id === updated.id ? updated : f))}
                  onBack={() => setActiveTab('form_manager')}
                  onPublish={() => setActiveTab('form_share')}
               />
            )}

            {activeTab === 'form_analytics' && selectedFormId && (
               <FormAnalytics 
                  form={forms.find(f => f.id === selectedFormId)!}
                  submissions={formSubmissions.filter(s => s.formId === selectedFormId)}
                  onDeleteSubmission={(id) => setFormSubmissions(formSubmissions.filter(s => s.id !== id))}
                  onBack={() => setActiveTab('form_manager')}
                  onShare={() => setActiveTab('form_share')}
               />
            )}

            {activeTab === 'form_share' && selectedFormId && (
               <FormShareDashboard 
                  form={forms.find(f => f.id === selectedFormId)!}
                  onBack={() => setActiveTab('form_manager')}
                  onPreview={() => {
                     setActiveTab('public_view_simulation');
                     setDesignerMode('PREVIEW');
                  }}
                  customDomain={domain}
               />
            )}

            {activeTab === 'settings' && <SystemSettings 
               onSave={(s) => {
                  setDomain(s.domain);
                  setAttendanceConfig(s.attendance);
                  setPermissionSettings(s.permissions);
                  setLoginConfig(s.loginConfig);
                  setRegistrationConfig(s.registrationConfig);
               }}
               initialDomain={domain}
               initialAttendanceConfig={attendanceConfig}
               initialPermissionSettings={permissionSettings}
               initialLoginConfig={loginConfig}
               initialRegistrationConfig={registrationConfig}
               adminUsers={adminUsers}
               onAddAdmin={(u) => { setAdminUsers([...adminUsers, u]); return true; }}
               onDeleteAdmin={(u) => setAdminUsers(adminUsers.filter(user => user.username !== u))}
               onUpdateAdminPassword={(u, p) => setAdminUsers(adminUsers.map(user => user.username === u ? { ...user, password: p } : user))}
            />}

            {activeTab === 'training_checkin' && <TrainingCheckinManager 
               queue={queue}
               registrationList={registrationList}
               onSiteRecords={onSiteRecords}
               onUpdateOnSiteRecords={setOnSiteRecords}
               staffList={staffList}
               forms={forms}
               formSubmissions={formSubmissions}
               onUpdateRegistration={setRegistrationList}
               onBatchAddStaff={(list) => setStaffList([...staffList, ...list])}
               onManageForm={(id, mode) => {
                  setSelectedFormId(id);
                  if (mode === 'EDIT') setActiveTab('form_designer');
                  else if (mode === 'ANALYTICS') setActiveTab('form_analytics');
                  else if (mode === 'PREVIEW') setActiveTab('form_share');
               }}
               permissionSettings={permissionSettings}
               session={session}
               registrationConfig={registrationConfig}
            />}

            {activeTab === 'checkin_terminal' && <CheckInSystem 
               queue={queue}
               registrationList={registrationList}
               onSiteRecords={onSiteRecords}
               staffList={staffList}
               onCheckIn={(sid) => {
                  if (queue.some(q => q.staffId === sid)) return;
                  // Find name from any list
                  const p = registrationList.find(r => r.id === sid) || onSiteRecords.find(r => r.id === sid) || staffList.find(s => s.id === sid);
                  if (p) {
                     setQueue([...queue, {
                        id: crypto.randomUUID(),
                        ticketNumber: `A${String(queue.length + 1).padStart(3, '0')}`,
                        staffId: sid,
                        staffName: p.name,
                        status: 'WAITING',
                        checkInTime: new Date().toISOString()
                     }]);
                  }
               }}
               onClearQueue={() => setQueue([])}
               onUpdateTicketStatus={(tid, status) => setQueue(queue.map(q => q.id === tid ? { ...q, status } : q))}
            />}
         </div>
      </main>
    </div>
  );
};

