import React, { useState, useEffect } from 'react';
import { User, Lock, ArrowRight, Smartphone, CreditCard, AlertCircle, Check, Zap, Briefcase, ShieldCheck, UserPlus } from 'lucide-react';
import { AdminUser, Staff, LoginConfig, RegistrationRecord } from '../types';

interface LoginProps {
  staffList: Staff[];
  registrationList: RegistrationRecord[];
  onSiteRecords?: RegistrationRecord[]; 
  onLogin: (userId: string, role: 'ADMIN' | 'USER') => void;
  adminUsers: AdminUser[];
  loginConfig?: LoginConfig;
}

type LoginMode = 'CANDIDATE' | 'STAFF' | 'ADMIN';

const Login: React.FC<LoginProps> = ({ staffList, registrationList, onSiteRecords = [], onLogin, adminUsers, loginConfig }) => {
  // Login Mode State - Default to CANDIDATE as it's the first tab now
  const [loginMode, setLoginMode] = useState<LoginMode>('CANDIDATE');

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    idCardSuffix: '', // Last 6 digits
    adminUser: '',
    adminPass: '',
    captchaInput: ''
  });

  const [captchaCode, setCaptchaCode] = useState('');
  const [countdown, setCountdown] = useState(60); 
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Status Feedback View
  const [loginStatusView, setLoginStatusView] = useState<'NORMAL' | 'REJECTED' | 'WAITING_GROUP'>('NORMAL');

  // Generate Captcha
  const generateCaptcha = () => {
    const chars = '23456789ABCDEFGHJKLMNPQRSTUVWXYZ';
    let result = '';
    for (let i = 0; i < 4; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    setCaptchaCode(result);
    setCountdown(60); 
  };

  // Initial Captcha & Auto Refresh Timer (60s)
  useEffect(() => {
    generateCaptcha();
    const interval = setInterval(() => generateCaptcha(), 60000);
    const countdownInterval = setInterval(() => {
      setCountdown((prev) => (prev > 0 ? prev - 1 : 60));
    }, 1000);

    return () => {
      clearInterval(interval);
      clearInterval(countdownInterval);
    };
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    setLoading(true);
    setTimeout(() => {
        setLoading(false);
        processLogin();
    }, 500);
  };

  const processLogin = () => {
    setLoginStatusView('NORMAL');

    // --- ADMIN LOGIN ---
    if (loginMode === 'ADMIN') {
      if (formData.captchaInput.toUpperCase() !== captchaCode) {
         setError('验证码错误');
         generateCaptcha();
         setFormData({...formData, captchaInput: ''});
         return;
      }
      const admin = adminUsers.find(u => u.username === formData.adminUser && u.password === formData.adminPass);
      if (admin) {
        onLogin(admin.username, 'ADMIN');
      } else {
        setError('账号或密码错误');
        generateCaptcha();
      }
      return;
    }

    // --- USER LOGIN (STAFF OR CANDIDATE) ---
    const { name, phone, idCardSuffix } = formData;
    if (!name || !phone || !idCardSuffix) {
       setError('请补全信息');
       return;
    }

    // 1. CANDIDATE MODE: Search in Registration List & OnSite Records
    if (loginMode === 'CANDIDATE') {
      // Combine lists for search
      const allCandidates = [...registrationList, ...onSiteRecords];
      const candidate = allCandidates.find(r => r.name === name && r.phone === phone);

      if (candidate) {
          const actualIdSuffix = candidate.idCard ? candidate.idCard.slice(-6) : '';
          // Only validate suffix if ID card exists in record
          if (candidate.idCard && actualIdSuffix !== idCardSuffix) {
              setError('身份校验失败，请检查身份证后6位');
              return;
          }
          // Allow candidates to login -> they will see IntervieweeDashboard
          onLogin(candidate.id, 'USER');
          return;
      } else {
        setError('未找到报名信息，请检查输入或联系管理员');
        return;
      }
    }

    // 2. STAFF MODE: Search only in Staff List (Official Employees)
    if (loginMode === 'STAFF') {
      const staff = staffList.find(s => s.name === name && s.phone === phone);

      if (staff) {
        const actualIdSuffix = staff.idCard ? staff.idCard.slice(-6) : '';
        if (actualIdSuffix !== idCardSuffix) {
           setError('身份校验失败，请检查身份证后6位');
           return;
        }

        if (staff.status === 'REJECTED') {
          setLoginStatusView('REJECTED');
          return;
        }

        onLogin(staff.id, 'USER');
        return;
      } else {
        setError('未找到该员工，请确认您已入职或切换到“面试/报名”入口');
        return;
      }
    }

    setError('未知登录错误');
  };

  const resetForm = () => {
    setLoginStatusView('NORMAL');
    setFormData({ name: '', phone: '', idCardSuffix: '', adminUser: '', adminPass: '', captchaInput: '' });
    generateCaptcha();
    setError('');
  };

  // --- Feedback Screens ---
  if (loginStatusView === 'REJECTED') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 font-sans p-4">
        <div className="bg-white p-8 rounded-3xl shadow-lg w-full max-w-xs border border-gray-100 animate-in zoom-in duration-300">
           <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-4 text-red-400 shadow-inner">
             <AlertCircle size={32} />
           </div>
           <h2 className="text-xl font-bold text-gray-800 mb-2 text-center">审核未通过</h2>
           <p className="text-gray-400 text-sm mb-6 text-center">非常抱歉，您暂时不符合录用标准。</p>
           <button onClick={resetForm} className="w-full py-3 rounded-xl font-bold bg-gray-100 text-gray-600 hover:bg-gray-200 transition-colors text-sm">返回</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-white font-sans selection:bg-indigo-100 selection:text-indigo-600">

      {/* LEFT (Desktop Only): Clean Aesthetic or Custom Image */}
      <div className="hidden lg:flex w-[40%] relative items-center justify-center bg-[#F8FAFC] overflow-hidden border-r border-gray-100">

         {/* Background Image / Abstract Graphic */}
         {loginConfig?.imageUrl ? (
            <img src={loginConfig.imageUrl} alt="Cover" className="absolute inset-0 w-full h-full object-cover z-0" />
         ) : (
            // Default Abstract Graphic
            <div className="relative z-10">
                <div className="w-64 h-80 bg-white rounded-[40px] shadow-2xl border border-gray-100 flex flex-col items-center justify-center relative overflow-hidden transform rotate-[-6deg] hover:rotate-0 transition-transform duration-500">
                   <div className="absolute top-0 left-0 w-full h-2 bg-indigo-500"></div>
                   <div className="flex-1 flex flex-col items-center justify-center w-full p-8 gap-4">
                      <div className="w-20 h-20 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 mb-2">
                         <Check size={40} strokeWidth={3} />
                      </div>
                      <div className="w-full space-y-3">
                         <div className="h-2 w-2/3 bg-gray-100 rounded-full mx-auto"></div>
                         <div className="h-2 w-1/2 bg-gray-100 rounded-full mx-auto"></div>
                      </div>
                   </div>
                   <div className="w-full p-4 bg-gray-50 border-t border-gray-100 flex justify-center">
                      <div className="w-8 h-8 rounded-full bg-gray-200"></div>
                   </div>
                </div>

                <div className="absolute -bottom-8 -right-12 bg-white p-4 rounded-2xl shadow-xl border border-gray-100 transform rotate-[8deg] animate-bounce-slow">
                   <div className="flex items-center gap-2">
                      <span className="w-3 h-3 rounded-full bg-green-500"></span>
                      <span className="text-xs font-bold text-gray-600">Checked In</span>
                   </div>
                </div>
            </div>
         )}

         {/* Overlay for image to ensure text contrast if we had text over it, but here we don't have text over image */}
         {loginConfig?.imageUrl && <div className="absolute inset-0 bg-black/10 z-0 pointer-events-none"></div>}
      </div>

      {/* RIGHT (Mobile & Desktop): Form */}
      <div className="w-full lg:w-[60%] flex-1 flex flex-col items-center justify-center p-6 md:p-12 bg-white">

        <div className="w-full max-w-sm space-y-8 animate-in slide-in-from-bottom-4 duration-500">
          {/* Header */}
          <div className="text-center space-y-2">
             <div className="inline-flex items-center justify-center w-14 h-14 bg-gray-900 text-white rounded-2xl mb-2 shadow-xl shadow-gray-200 transform hover:rotate-6 transition-transform overflow-hidden">
                {loginConfig?.logoUrl ? (
                   <img src={loginConfig.logoUrl} alt="Logo" className="w-full h-full object-cover" />
                ) : (
                   <Zap size={24} fill="currentColor" />
                )}
             </div>
             <h2 className="text-2xl font-black text-gray-900 tracking-tight">{loginConfig?.title || '签到小工具'}</h2>
             {loginConfig?.subtitle && <p className="text-gray-400 text-sm font-medium">{loginConfig.subtitle}</p>}
          </div>

          {/* Mode Tabs (Updated Order: Candidate -> Staff -> Admin) */}
          <div className="flex p-1 bg-gray-50 border border-gray-100 rounded-2xl">
             <button 
               onClick={() => { setLoginMode('CANDIDATE'); setError(''); }}
               className={`flex-1 py-2.5 text-xs font-bold rounded-xl transition-all flex flex-col items-center justify-center gap-1 ${loginMode === 'CANDIDATE' ? 'bg-white text-blue-600 shadow-sm border border-gray-100' : 'text-gray-400 hover:text-gray-600'}`}
             >
               <UserPlus size={14} /> 面试/报名
             </button>
             <button 
               onClick={() => { setLoginMode('STAFF'); setError(''); }}
               className={`flex-1 py-2.5 text-xs font-bold rounded-xl transition-all flex flex-col items-center justify-center gap-1 ${loginMode === 'STAFF' ? 'bg-white text-indigo-600 shadow-sm border border-gray-100' : 'text-gray-400 hover:text-gray-600'}`}
             >
               <Briefcase size={14} /> STAFF/编外
             </button>
             <button 
               onClick={() => { setLoginMode('ADMIN'); setError(''); }}
               className={`flex-1 py-2.5 text-xs font-bold rounded-xl transition-all flex flex-col items-center justify-center gap-1 ${loginMode === 'ADMIN' ? 'bg-white text-gray-900 shadow-sm border border-gray-100' : 'text-gray-400 hover:text-gray-600'}`}
             >
               <ShieldCheck size={14} /> 管理员后台
             </button>
          </div>

          {/* Form */}
          <form onSubmit={handleLogin} className="space-y-4">

            {loginMode !== 'ADMIN' ? (
              <div className="space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
                 <div className="relative group">
                    <User size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors" />
                    <input 
                      type="text" 
                      placeholder="姓名"
                      value={formData.name}
                      onChange={e => setFormData({...formData, name: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-sm font-medium placeholder-gray-400"
                    />
                 </div>
                 <div className="relative group">
                    <Smartphone size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors" />
                    <input 
                      type="tel" 
                      placeholder="手机号"
                      value={formData.phone}
                      onChange={e => setFormData({...formData, phone: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-sm font-medium placeholder-gray-400"
                    />
                 </div>
                 <div className="relative group">
                    <CreditCard size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors" />
                    <input 
                      type="text" 
                      maxLength={6}
                      placeholder="身份证后6位"
                      value={formData.idCardSuffix}
                      onChange={e => setFormData({...formData, idCardSuffix: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-sm font-medium placeholder-gray-400"
                    />
                 </div>
              </div>
            ) : (
              <div className="space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
                 <div className="relative group">
                    <User size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-gray-800 transition-colors" />
                    <input 
                      type="text" 
                      placeholder="管理员账号"
                      value={formData.adminUser}
                      onChange={e => setFormData({...formData, adminUser: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-gray-300 focus:ring-0 outline-none transition-all text-sm font-medium"
                    />
                 </div>
                 <div className="relative group">
                    <Lock size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-gray-800 transition-colors" />
                    <input 
                      type="password" 
                      placeholder="密码"
                      value={formData.adminPass}
                      onChange={e => setFormData({...formData, adminPass: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-gray-300 focus:ring-0 outline-none transition-all text-sm font-medium"
                    />
                 </div>
                 <div className="flex gap-2">
                    <input
                       type="text"
                       maxLength={4}
                       placeholder="验证码"
                       value={formData.captchaInput}
                       onChange={e => setFormData({...formData, captchaInput: e.target.value})}
                       className="flex-1 px-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-gray-300 outline-none transition-all text-sm font-medium text-center uppercase"
                    />
                    <div 
                      onClick={generateCaptcha}
                      className="w-28 bg-gray-100 rounded-2xl flex flex-col items-center justify-center cursor-pointer relative overflow-hidden group hover:bg-gray-200 transition-colors border border-transparent"
                    >
                        <span className="font-mono font-bold text-gray-600 text-lg tracking-widest z-10">{captchaCode}</span>
                        <div className="absolute bottom-0 left-0 h-1 bg-indigo-400 transition-all duration-1000 ease-linear opacity-50" style={{ width: `${(countdown/60)*100}%` }}></div>
                    </div>
                 </div>
              </div>
            )}

            {error && (
               <div className="bg-red-50 text-red-500 text-xs flex items-center justify-center gap-1.5 py-2.5 rounded-xl border border-red-100 animate-pulse font-medium">
                  <AlertCircle size={14} /> {error}
               </div>
            )}

            <button
               type="submit"
               disabled={loading}
               className={`w-full py-4 rounded-2xl font-bold text-base text-white shadow-xl flex items-center justify-center gap-2 transform active:scale-95 transition-all
                 ${loginMode === 'ADMIN' 
                   ? 'bg-gray-900 hover:bg-black shadow-gray-200' 
                   : loginMode === 'CANDIDATE' 
                     ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'
                     : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'}
               `}
            >
               {loading ? '处理中...' : (
                 <>
                   {loginMode === 'ADMIN' ? '进入后台' : loginMode === 'CANDIDATE' ? '进入面试/等待区' : '员工登录'} <ArrowRight size={18} />
                 </>
               )}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

