import React, { useState, useEffect } from 'react';
import { User, Lock, ArrowRight, Smartphone, CreditCard, AlertCircle, Check, Zap, Briefcase, ShieldCheck, UserPlus } from 'lucide-react';
import { AdminUser, Staff, LoginConfig, RegistrationRecord } from '../types';

interface LoginProps {
  staffList: Staff[];
  registrationList: RegistrationRecord[];
  onSiteRecords?: RegistrationRecord[]; // Added optional prop
  onLogin: (userId: string, role: 'ADMIN' | 'USER') => void;
  adminUsers: AdminUser[];
  loginConfig?: LoginConfig;
}

type LoginMode = 'STAFF' | 'CANDIDATE' | 'ADMIN';

const Login: React.FC<LoginProps> = ({ staffList, registrationList, onSiteRecords = [], onLogin, adminUsers, loginConfig }) => {
  // Login Mode State
  const [loginMode, setLoginMode] = useState<LoginMode>('STAFF');

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    idCardSuffix: '', // Last 6 digits
    adminUser: '',
    adminPass: '',
    captchaInput: ''
  });

  const [captchaCode, setCaptchaCode] = useState('');
  const [countdown, setCountdown] = useState(60); 
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Status Feedback View
  const [loginStatusView, setLoginStatusView] = useState<'NORMAL' | 'REJECTED' | 'WAITING_GROUP'>('NORMAL');

  // Generate Captcha
  const generateCaptcha = () => {
    const chars = '23456789ABCDEFGHJKLMNPQRSTUVWXYZ';
    let result = '';
    for (let i = 0; i < 4; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    setCaptchaCode(result);
    setCountdown(60); 
  };

  // Initial Captcha & Auto Refresh Timer (60s)
  useEffect(() => {
    generateCaptcha();
    const interval = setInterval(() => generateCaptcha(), 60000);
    const countdownInterval = setInterval(() => {
      setCountdown((prev) => (prev > 0 ? prev - 1 : 60));
    }, 1000);

    return () => {
      clearInterval(interval);
      clearInterval(countdownInterval);
    };
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    setLoading(true);
    setTimeout(() => {
        setLoading(false);
        processLogin();
    }, 500);
  };

  const processLogin = () => {
    setLoginStatusView('NORMAL');

    // --- ADMIN LOGIN ---
    if (loginMode === 'ADMIN') {
      if (formData.captchaInput.toUpperCase() !== captchaCode) {
         setError('验证码错误');
         generateCaptcha();
         setFormData({...formData, captchaInput: ''});
         return;
      }
      const admin = adminUsers.find(u => u.username === formData.adminUser && u.password === formData.adminPass);
      if (admin) {
        onLogin(admin.username, 'ADMIN');
      } else {
        setError('账号或密码错误');
        generateCaptcha();
      }
      return;
    }

    // --- USER LOGIN (STAFF OR CANDIDATE) ---
    const { name, phone, idCardSuffix } = formData;
    if (!name || !phone || !idCardSuffix) {
       setError('请补全信息');
       return;
    }

    // 1. STAFF MODE: Search only in Staff List (Official Employees)
    if (loginMode === 'STAFF') {
      const staff = staffList.find(s => s.name === name && s.phone === phone);

      if (staff) {
        const actualIdSuffix = staff.idCard ? staff.idCard.slice(-6) : '';
        if (actualIdSuffix !== idCardSuffix) {
           setError('身份校验失败，请检查身份证后6位');
           return;
        }

        if (staff.status === 'REJECTED') {
          setLoginStatusView('REJECTED');
          return;
        }

        onLogin(staff.id, 'USER');
        return;
      } else {
        setError('未找到该员工，请确认您已入职或切换到“面试/报名”入口');
        return;
      }
    }

    // 2. CANDIDATE MODE: Search in Registration List & OnSite Records
    if (loginMode === 'CANDIDATE') {
      // Combine lists for search
      const allCandidates = [...registrationList, ...onSiteRecords];
      const candidate = allCandidates.find(r => r.name === name && r.phone === phone);

      if (candidate) {
          const actualIdSuffix = candidate.idCard ? candidate.idCard.slice(-6) : '';
          // Only validate suffix if ID card exists in record
          if (candidate.idCard && actualIdSuffix !== idCardSuffix) {
              setError('身份校验失败，请检查身份证后6位');
              return;
          }
          // Allow candidates to login -> they will see IntervieweeDashboard
          onLogin(candidate.id, 'USER');
          return;
      } else {
        setError('未找到报名信息，请检查输入或联系管理员');
        return;
      }
    }

    setError('未知登录错误');
  };

  const resetForm = () => {
    setLoginStatusView('NORMAL');
    setFormData({ name: '', phone: '', idCardSuffix: '', adminUser: '', adminPass: '', captchaInput: '' });
    generateCaptcha();
    setError('');
  };

  // --- Feedback Screens ---
  if (loginStatusView === 'REJECTED') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 font-sans p-4">
        <div className="bg-white p-8 rounded-3xl shadow-lg w-full max-w-xs border border-gray-100 animate-in zoom-in duration-300">
           <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-4 text-red-400 shadow-inner">
             <AlertCircle size={32} />
           </div>
           <h2 className="text-xl font-bold text-gray-800 mb-2 text-center">审核未通过</h2>
           <p className="text-gray-400 text-sm mb-6 text-center">非常抱歉，您暂时不符合录用标准。</p>
           <button onClick={resetForm} className="w-full py-3 rounded-xl font-bold bg-gray-100 text-gray-600 hover:bg-gray-200 transition-colors text-sm">返回</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-white font-sans selection:bg-indigo-100 selection:text-indigo-600">

      {/* LEFT (Desktop Only): Clean Aesthetic or Custom Image */}
      <div className="hidden lg:flex w-[40%] relative items-center justify-center bg-[#F8FAFC] overflow-hidden border-r border-gray-100">

         {/* Background Image / Abstract Graphic */}
         {loginConfig?.imageUrl ? (
            <img src={loginConfig.imageUrl} alt="Cover" className="absolute inset-0 w-full h-full object-cover z-0" />
         ) : (
            // Default Abstract Graphic
            <div className="relative z-10">
                <div className="w-64 h-80 bg-white rounded-[40px] shadow-2xl border border-gray-100 flex flex-col items-center justify-center relative overflow-hidden transform rotate-[-6deg] hover:rotate-0 transition-transform duration-500">
                   <div className="absolute top-0 left-0 w-full h-2 bg-indigo-500"></div>
                   <div className="flex-1 flex flex-col items-center justify-center w-full p-8 gap-4">
                      <div className="w-20 h-20 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 mb-2">
                         <Check size={40} strokeWidth={3} />
                      </div>
                      <div className="w-full space-y-3">
                         <div className="h-2 w-2/3 bg-gray-100 rounded-full mx-auto"></div>
                         <div className="h-2 w-1/2 bg-gray-100 rounded-full mx-auto"></div>
                      </div>
                   </div>
                   <div className="w-full p-4 bg-gray-50 border-t border-gray-100 flex justify-center">
                      <div className="w-8 h-8 rounded-full bg-gray-200"></div>
                   </div>
                </div>

                <div className="absolute -bottom-8 -right-12 bg-white p-4 rounded-2xl shadow-xl border border-gray-100 transform rotate-[8deg] animate-bounce-slow">
                   <div className="flex items-center gap-2">
                      <span className="w-3 h-3 rounded-full bg-green-500"></span>
                      <span className="text-xs font-bold text-gray-600">Checked In</span>
                   </div>
                </div>
            </div>
         )}

         {/* Overlay for image to ensure text contrast if we had text over it, but here we don't have text over image */}
         {loginConfig?.imageUrl && <div className="absolute inset-0 bg-black/10 z-0 pointer-events-none"></div>}
      </div>

      {/* RIGHT (Mobile & Desktop): Form */}
      <div className="w-full lg:w-[60%] flex-1 flex flex-col items-center justify-center p-6 md:p-12 bg-white">

        <div className="w-full max-w-sm space-y-8 animate-in slide-in-from-bottom-4 duration-500">
          {/* Header */}
          <div className="text-center space-y-2">
             <div className="inline-flex items-center justify-center w-14 h-14 bg-gray-900 text-white rounded-2xl mb-2 shadow-xl shadow-gray-200 transform hover:rotate-6 transition-transform overflow-hidden">
                {loginConfig?.logoUrl ? (
                   <img src={loginConfig.logoUrl} alt="Logo" className="w-full h-full object-cover" />
                ) : (
                   <Zap size={24} fill="currentColor" />
                )}
             </div>
             <h2 className="text-2xl font-black text-gray-900 tracking-tight">{loginConfig?.title || '签到小工具'}</h2>
             {loginConfig?.subtitle && <p className="text-gray-400 text-sm font-medium">{loginConfig.subtitle}</p>}
          </div>

          {/* Mode Tabs (Updated for 3 options) */}
          <div className="flex p-1 bg-gray-50 border border-gray-100 rounded-2xl">
             <button 
               onClick={() => { setLoginMode('STAFF'); setError(''); }}
               className={`flex-1 py-2.5 text-xs font-bold rounded-xl transition-all flex flex-col items-center justify-center gap-1 ${loginMode === 'STAFF' ? 'bg-white text-indigo-600 shadow-sm border border-gray-100' : 'text-gray-400 hover:text-gray-600'}`}
             >
               <Briefcase size={14} /> 正式员工
             </button>
             <button 
               onClick={() => { setLoginMode('CANDIDATE'); setError(''); }}
               className={`flex-1 py-2.5 text-xs font-bold rounded-xl transition-all flex flex-col items-center justify-center gap-1 ${loginMode === 'CANDIDATE' ? 'bg-white text-blue-600 shadow-sm border border-gray-100' : 'text-gray-400 hover:text-gray-600'}`}
             >
               <UserPlus size={14} /> 面试/报名
             </button>
             <button 
               onClick={() => { setLoginMode('ADMIN'); setError(''); }}
               className={`flex-1 py-2.5 text-xs font-bold rounded-xl transition-all flex flex-col items-center justify-center gap-1 ${loginMode === 'ADMIN' ? 'bg-white text-gray-900 shadow-sm border border-gray-100' : 'text-gray-400 hover:text-gray-600'}`}
             >
               <ShieldCheck size={14} /> 管理后台
             </button>
          </div>

          {/* Form */}
          <form onSubmit={handleLogin} className="space-y-4">

            {loginMode !== 'ADMIN' ? (
              <div className="space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
                 <div className="relative group">
                    <User size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors" />
                    <input 
                      type="text" 
                      placeholder="姓名"
                      value={formData.name}
                      onChange={e => setFormData({...formData, name: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-sm font-medium placeholder-gray-400"
                    />
                 </div>
                 <div className="relative group">
                    <Smartphone size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors" />
                    <input 
                      type="tel" 
                      placeholder="手机号"
                      value={formData.phone}
                      onChange={e => setFormData({...formData, phone: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-sm font-medium placeholder-gray-400"
                    />
                 </div>
                 <div className="relative group">
                    <CreditCard size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-indigo-500 transition-colors" />
                    <input 
                      type="text" 
                      maxLength={6}
                      placeholder="身份证后6位"
                      value={formData.idCardSuffix}
                      onChange={e => setFormData({...formData, idCardSuffix: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-sm font-medium placeholder-gray-400"
                    />
                 </div>
              </div>
            ) : (
              <div className="space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
                 <div className="relative group">
                    <User size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-gray-800 transition-colors" />
                    <input 
                      type="text" 
                      placeholder="管理员账号"
                      value={formData.adminUser}
                      onChange={e => setFormData({...formData, adminUser: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-gray-300 focus:ring-0 outline-none transition-all text-sm font-medium"
                    />
                 </div>
                 <div className="relative group">
                    <Lock size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-gray-800 transition-colors" />
                    <input 
                      type="password" 
                      placeholder="密码"
                      value={formData.adminPass}
                      onChange={e => setFormData({...formData, adminPass: e.target.value})}
                      className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-gray-300 focus:ring-0 outline-none transition-all text-sm font-medium"
                    />
                 </div>
                 <div className="flex gap-2">
                    <input
                       type="text"
                       maxLength={4}
                       placeholder="验证码"
                       value={formData.captchaInput}
                       onChange={e => setFormData({...formData, captchaInput: e.target.value})}
                       className="flex-1 px-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-gray-300 outline-none transition-all text-sm font-medium text-center uppercase"
                    />
                    <div 
                      onClick={generateCaptcha}
                      className="w-28 bg-gray-100 rounded-2xl flex flex-col items-center justify-center cursor-pointer relative overflow-hidden group hover:bg-gray-200 transition-colors border border-transparent"
                    >
                        <span className="font-mono font-bold text-gray-600 text-lg tracking-widest z-10">{captchaCode}</span>
                        <div className="absolute bottom-0 left-0 h-1 bg-indigo-400 transition-all duration-1000 ease-linear opacity-50" style={{ width: `${(countdown/60)*100}%` }}></div>
                    </div>
                 </div>
              </div>
            )}

            {error && (
               <div className="bg-red-50 text-red-500 text-xs flex items-center justify-center gap-1.5 py-2.5 rounded-xl border border-red-100 animate-pulse font-medium">
                  <AlertCircle size={14} /> {error}
               </div>
            )}

            <button
               type="submit"
               disabled={loading}
               className={`w-full py-4 rounded-2xl font-bold text-base text-white shadow-xl flex items-center justify-center gap-2 transform active:scale-95 transition-all
                 ${loginMode === 'ADMIN' 
                   ? 'bg-gray-900 hover:bg-black shadow-gray-200' 
                   : loginMode === 'CANDIDATE' 
                     ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'
                     : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'}
               `}
            >
               {loading ? '处理中...' : (
                 <>
                   {loginMode === 'ADMIN' ? '进入后台' : loginMode === 'CANDIDATE' ? '进入面试/等待区' : '员工登录'} <ArrowRight size={18} />
                 </>
               )}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './index.css'; // Assuming styles might be here, if not it's fine.

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import StaffManager from './components/StaffManager';
import OutsourcedManager from './components/OutsourcedManager';
import TrainingCheckinManager from './components/TrainingCheckinManager';
import StaffScheduleManager from './components/StaffScheduleManager';
import FormManager from './components/FormManager';
import FormDesigner from './components/FormDesigner';
import FormAnalytics from './components/FormAnalytics';
import FormShareDashboard from './components/FormShareDashboard';
import PublicDynamicForm from './components/PublicDynamicForm';
import SystemSettings from './components/SystemSettings';
import Interview from './components/Interview';
import TalentPool from './components/TalentPool';
import AllStaffOverview from './components/AllStaffOverview';
import IntervieweeDashboard from './components/IntervieweeDashboard';
import StaffDashboard from './components/StaffDashboard';
import AttendanceReports from './components/AttendanceReports';
import AnnouncementManager from './components/AnnouncementManager';
import CheckInSystem from './components/CheckInSystem';

import { 
  Staff, RegistrationRecord, QueueTicket, Group, Announcement, 
  AttendanceRecord, AttendanceConfig, PermissionSettings, LoginConfig, 
  RegistrationConfig, AdminUser, UserSession, FormTemplate, FormSubmission, 
  InterviewSession, ScheduleData, StaffStatus
} from './types';
import { 
  LayoutDashboard, Users, ClipboardList, Calendar, FileText, Settings, 
  UserCheck, Mic, Award, Briefcase, BarChart3, Megaphone, ScanLine, LogOut, 
  Menu, X
} from 'lucide-react';

// Mock Admin User
const DEFAULT_ADMINS: AdminUser[] = [
  { username: 'admin', password: 'password' }
];

const App: React.FC = () => {
  // --- Global State ---
  const [session, setSession] = useState<UserSession | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [sidebarOpen, setSidebarOpen] = useState(true);

  // Data Stores (In real app, fetch from API)
  const [staffList, setStaffList] = useState<Staff[]>([]);
  const [registrationList, setRegistrationList] = useState<RegistrationRecord[]>([]);
  const [onSiteRecords, setOnSiteRecords] = useState<RegistrationRecord[]>([]);
  const [queue, setQueue] = useState<QueueTicket[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [forms, setForms] = useState<FormTemplate[]>([]);
  const [formSubmissions, setFormSubmissions] = useState<FormSubmission[]>([]);
  const [interviewSessions, setInterviewSessions] = useState<InterviewSession[]>([]);
  const [scheduleData, setScheduleData] = useState<ScheduleData>({ headers: [], dynamicHeaders: [], rows: [] });
  const [adminUsers, setAdminUsers] = useState<AdminUser[]>(DEFAULT_ADMINS);

  // Configs
  const [attendanceConfig, setAttendanceConfig] = useState<AttendanceConfig>({ startTime: '09:00', endTime: '18:00', overtimeStart: '19:00' });
  const [permissionSettings, setPermissionSettings] = useState<PermissionSettings>({
    allowLeaderExport: true,
    allowLeaderBroadcast: true,
    allowStaffViewTeam: true,
    showSensitiveInfo: true,
    enableCheckIn: true
  });
  const [loginConfig, setLoginConfig] = useState<LoginConfig>({
    title: 'Staff Management',
    subtitle: 'Efficiency & Growth',
    imageUrl: '',
    logoUrl: ''
  });
  const [registrationConfig, setRegistrationConfig] = useState<RegistrationConfig>({ masterPrefix: 'M', onSitePrefix: 'S' });

  // Form Manager State
  const [selectedFormId, setSelectedFormId] = useState<string | null>(null);
  const [designerMode, setDesignerMode] = useState<'EDIT' | 'ANALYTICS' | 'PREVIEW' | 'SIMULATE'>('EDIT');

  // --- Persistence (Simple LocalStorage) ---
  useEffect(() => {
    const savedSession = localStorage.getItem('app_session');
    if (savedSession) setSession(JSON.parse(savedSession));

    // Load mock/saved data here if needed
  }, []);

  useEffect(() => {
    if (session) localStorage.setItem('app_session', JSON.stringify(session));
    else localStorage.removeItem('app_session');
  }, [session]);

  // --- Handlers ---

  const handleLogin = (userId: string, role: 'ADMIN' | 'USER') => {
    let currentUser: Staff | undefined;
    if (role === 'USER') {
      currentUser = staffList.find(s => s.id === userId);
      // Fallback for candidates not yet in staff list but in registration
      if (!currentUser) {
         const candidate = [...registrationList, ...onSiteRecords].find(r => r.id === userId);
         if (candidate) {
            currentUser = {
               id: candidate.id,
               name: candidate.name,
               idCard: candidate.idCard || '',
               avatar: '',
               status: 'PENDING',
               roles: [],
               joinDate: new Date().toISOString(),
               registrationNumber: candidate.registrationNumber
            };
         }
      }
    }
    setSession({ userId, role, staff: currentUser });
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setSession(null);
    setActiveTab('dashboard');
  };

  const handleClockIn = (photoUrl: string, status: 'NORMAL' | 'LATE' | 'EARLY_LEAVE' | 'OVERTIME', timestamp: string) => {
    if (!session?.staff) return;
    const newRecord: AttendanceRecord = {
      id: crypto.randomUUID(),
      staffId: session.staff.id,
      timestamp,
      type: 'IN',
      photoUrl,
      status
    };
    setAttendanceRecords(prev => [...prev, newRecord]);
  };

  const handleClockOut = (photoUrl: string, status: 'NORMAL' | 'LATE' | 'EARLY_LEAVE' | 'OVERTIME', timestamp: string) => {
    if (!session?.staff) return;
    const newRecord: AttendanceRecord = {
      id: crypto.randomUUID(),
      staffId: session.staff.id,
      timestamp,
      type: 'OUT',
      photoUrl,
      status
    };
    setAttendanceRecords(prev => [...prev, newRecord]);
  };

  const handleQueueCheckIn = (staffId: string) => {
    // Check if already in queue
    if (queue.some(t => t.staffId === staffId)) return;

    let personName = 'Unknown';
    const staff = staffList.find(s => s.id === staffId);
    if (staff) personName = staff.name;
    else {
       const reg = registrationList.find(r => r.id === staffId) || onSiteRecords.find(r => r.id === staffId);
       if (reg) personName = reg.name;
    }

    const newTicket: QueueTicket = {
      id: crypto.randomUUID(),
      ticketNumber: `A${String(queue.length + 1).padStart(3, '0')}`,
      staffId,
      staffName: personName,
      status: 'WAITING',
      checkInTime: new Date().toISOString()
    };
    setQueue(prev => [...prev, newTicket]);
  };

  const handleFormSubmit = (submission: FormSubmission) => {
    setFormSubmissions(prev => [...prev, submission]);
    setForms(prev => prev.map(f => f.id === submission.formId ? { ...f, submissionCount: f.submissionCount + 1 } : f));
    // If simulation, return to designer
    if (activeTab === 'public_view_simulation') {
       if (session) {
          setActiveTab(designerMode === 'PREVIEW' ? 'form_designer' : 'form_manager');
       } else {
          setActiveTab('login');
       }
    }
  };

  // --- Render Logic ---

  // 1. Public View Simulation (Form)
  if (activeTab === 'public_view_simulation' && selectedFormId) {
     const form = forms.find(f => f.id === selectedFormId);
     if (form) return <PublicDynamicForm form={form} onSubmit={handleFormSubmit} onCancel={() => { if (session) { if (designerMode === 'PREVIEW') setActiveTab('form_designer'); else setActiveTab('form_manager'); } else setActiveTab('login'); }} />;
  }

  // 2. Login Screen
  if (!session) {
     return <Login 
        staffList={staffList} 
        registrationList={registrationList} 
        onSiteRecords={onSiteRecords} 
        onLogin={handleLogin} 
        adminUsers={adminUsers} 
        loginConfig={loginConfig} 
     />;
  }

  // 3. Authenticated App
  const isLeader = session.role === 'USER' && session.staff?.roles.some(r => r.isLeader);

  // Sidebar Navigation Items
  const menuItems = [
    { id: 'dashboard', label: '工作台', icon: LayoutDashboard, roles: ['ADMIN', 'USER'] },
    { id: 'staff_candidates', label: '面试/候选人', icon: UserCheck, roles: ['ADMIN'] },
    { id: 'staff_employees', label: '正式员工', icon: Users, roles: ['ADMIN'] },
    { id: 'all_staff_overview', label: 'STAFF总览', icon: Users, roles: ['USER'] }, // Visible to leaders?
    { id: 'outsourced', label: '编外管理', icon: Briefcase, roles: ['ADMIN'] },
    { id: 'checkin_manager', label: '培训/签到管理', icon: ClipboardList, roles: ['ADMIN'] },
    { id: 'checkin_terminal', label: '扫码核销终端', icon: ScanLine, roles: ['ADMIN', 'LEADER'] },
    { id: 'schedule', label: '排班管理', icon: Calendar, roles: ['ADMIN'] },
    { id: 'form_manager', label: '表单中心', icon: FileText, roles: ['ADMIN'] },
    { id: 'interview', label: 'AI面试助手', icon: Mic, roles: ['ADMIN'] },
    { id: 'talent_pool', label: '人才库', icon: Award, roles: ['ADMIN'] },
    { id: 'attendance_reports', label: '考勤报表', icon: BarChart3, roles: ['ADMIN', 'LEADER'] },
    { id: 'announcements', label: '公告管理', icon: Megaphone, roles: ['ADMIN', 'LEADER'] },
    { id: 'settings', label: '系统设置', icon: Settings, roles: ['ADMIN'] },
  ];

  const visibleMenuItems = menuItems.filter(item => {
    if (session.role === 'ADMIN') return true;
    if (session.role === 'USER') {
       if (item.roles.includes('USER')) return true;
       if (isLeader && item.roles.includes('LEADER')) return true;
    }
    return false;
  });

  return (
    <div className="flex h-screen bg-[#F3F4F6] font-sans overflow-hidden">

      {/* Sidebar */}
      <aside className={`bg-white border-r border-gray-200 flex-col transition-all duration-300 z-30 ${sidebarOpen ? 'w-64' : 'w-20'} hidden md:flex`}>
         <div className="p-6 flex items-center gap-3 border-b border-gray-100 h-20">
            {loginConfig.logoUrl ? (
               <img src={loginConfig.logoUrl} className="w-8 h-8 object-contain" alt="Logo" />
            ) : (
               <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-lg shrink-0">S</div>
            )}
            {sidebarOpen && <span className="font-bold text-gray-800 text-lg tracking-tight truncate">{loginConfig.title}</span>}
         </div>

         <div className="flex-1 overflow-y-auto py-6 px-3 space-y-1 custom-scrollbar">
            {visibleMenuItems.map(item => (
               <button
                  key={item.id}
                  onClick={() => setActiveTab(item.id)}
                  className={`w-full flex items-center gap-3 px-3 py-3 rounded-xl transition-all group relative ${
                     activeTab === item.id 
                        ? 'bg-indigo-50 text-indigo-600 font-bold shadow-sm' 
                        : 'text-gray-500 hover:bg-gray-50 hover:text-gray-900'
                  }`}
                  title={!sidebarOpen ? item.label : ''}
               >
                  <item.icon size={20} className={activeTab === item.id ? 'text-indigo-600' : 'text-gray-400 group-hover:text-gray-600'} />
                  {sidebarOpen && <span>{item.label}</span>}
                  {!sidebarOpen && activeTab === item.id && <div className="absolute left-0 top-2 bottom-2 w-1 bg-indigo-600 rounded-r-full"></div>}
               </button>
            ))}
         </div>

         <div className="p-4 border-t border-gray-100">
            <button 
               onClick={handleLogout}
               className={`w-full flex items-center gap-3 px-3 py-3 rounded-xl text-red-500 hover:bg-red-50 transition-colors ${!sidebarOpen && 'justify-center'}`}
            >
               <LogOut size={20} />
               {sidebarOpen && <span className="font-medium">退出登录</span>}
            </button>
         </div>
      </aside>

      {/* Mobile Header / Sidebar Toggle */}
      <div className="md:hidden fixed top-0 left-0 right-0 bg-white border-b border-gray-200 p-4 z-40 flex justify-between items-center">
         <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold">S</div>
            <span className="font-bold text-gray-800">{loginConfig.title}</span>
         </div>
         <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 text-gray-600">
            {sidebarOpen ? <X /> : <Menu />}
         </button>
      </div>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pt-16 md:pt-0 relative">
         <div className="p-6 md:p-8 max-w-[1600px] mx-auto min-h-full">

            {activeTab === 'dashboard' && (
               session.role === 'ADMIN' ? (
                  <Dashboard 
                     attendanceRecords={attendanceRecords}
                     queueData={queue}
                     announcements={announcements}
                     isAdmin={true}
                     staffList={staffList}
                     groups={groups}
                     currentUser={session.staff}
                  />
               ) : (
                  // User Dashboard: Check if candidate or employee
                  (session.staff?.status === 'PENDING' || session.staff?.status === 'INTERVIEWED') && session.staff.roles.length === 0 ? (
                     <IntervieweeDashboard 
                        staff={session.staff}
                        onLogout={handleLogout}
                        myTicket={queue.find(t => t.staffId === session.staff?.id)}
                        ticketsAhead={queue.filter(t => t.status === 'WAITING' && t.id < (queue.find(mq => mq.staffId === session.staff?.id)?.id || '')).length}
                     />
                  ) : (
                     <StaffDashboard 
                        currentUser={session.staff!}
                        group={groups.find(g => session.staff?.roles.some(r => r.groupId === g.id))}
                        leaders={staffList.filter(s => s.roles.some(r => session.staff?.roles.some(myR => myR.groupId === r.groupId) && r.isLeader))}
                        staffList={staffList}
                        announcements={announcements}
                        attendanceStatus={attendanceRecords.some(r => r.staffId === session.staff?.id && r.type === 'IN' && !attendanceRecords.some(out => out.staffId === session.staff?.id && out.type === 'OUT' && new Date(out.timestamp) > new Date(r.timestamp))) ? 'CLOCKED_IN' : 'CLOCKED_OUT'}
                        attendanceHistory={attendanceRecords.filter(r => r.staffId === session.staff?.id && new Date(r.timestamp).toDateString() === new Date().toDateString())}
                        attendanceConfig={attendanceConfig}
                        onClockIn={handleClockIn}
                        onClockOut={handleClockOut}
                     />
                  )
               )
            )}

            {activeTab === 'staff_candidates' && (
               <StaffManager 
                  viewMode="CANDIDATES"
                  staffList={staffList} 
                  groups={groups}
                  onUpdateStaff={(s) => setStaffList(prev => prev.map(old => old.id === s.id ? s : old))}
                  onAddStaff={(s) => setStaffList(prev => [...prev, s])}
                  onBatchAddStaff={(list) => setStaffList(prev => [...prev, ...list])}
                  onAddGroup={(g) => setGroups(prev => [...prev, g])}
                  onDeleteGroup={(gid) => setGroups(prev => prev.filter(g => g.id !== gid))}
               />
            )}

            {activeTab === 'staff_employees' && (
               <StaffManager 
                  viewMode="EMPLOYEES"
                  staffList={staffList} 
                  groups={groups}
                  onUpdateStaff={(s) => setStaffList(prev => prev.map(old => old.id === s.id ? s : old))}
                  onAddStaff={(s) => setStaffList(prev => [...prev, s])}
                  onBatchAddStaff={(list) => setStaffList(prev => [...prev, ...list])}
                  onAddGroup={(g) => setGroups(prev => [...prev, g])}
                  onDeleteGroup={(gid) => setGroups(prev => prev.filter(g => g.id !== gid))}
               />
            )}

            {activeTab === 'outsourced' && (
               <OutsourcedManager 
                  staffList={staffList}
                  groups={groups}
                  registrationList={registrationList}
                  onSiteRecords={onSiteRecords}
                  permissionSettings={permissionSettings}
                  onUpdateStaff={(s) => setStaffList(prev => prev.map(old => old.id === s.id ? s : old))}
                  onAddStaff={(s) => setStaffList(prev => [...prev, s])}
                  onBatchAddStaff={(list) => setStaffList(prev => [...prev, ...list])}
                  onAddGroup={(g) => setGroups(prev => [...prev, g])}
                  onUpdateGroup={(g) => setGroups(prev => prev.map(old => old.id === g.id ? g : old))}
                  onDeleteGroup={(gid) => setGroups(prev => prev.filter(g => g.id !== gid))}
               />
            )}

            {activeTab === 'checkin_manager' && (
               <TrainingCheckinManager 
                  queue={queue}
                  registrationList={registrationList}
                  onSiteRecords={onSiteRecords}
                  onUpdateOnSiteRecords={setOnSiteRecords}
                  staffList={staffList}
                  forms={forms}
                  formSubmissions={formSubmissions}
                  onUpdateRegistration={setRegistrationList}
                  onBatchAddStaff={(list) => setStaffList(prev => [...prev, ...list])}
                  permissionSettings={permissionSettings}
                  session={session}
                  registrationConfig={registrationConfig}
               />
            )}

            {activeTab === 'checkin_terminal' && (
               <CheckInSystem 
                  queue={queue}
                  registrationList={registrationList}
                  onSiteRecords={onSiteRecords}
                  staffList={staffList}
                  onCheckIn={handleQueueCheckIn}
                  onClearQueue={() => setQueue([])}
                  onUpdateTicketStatus={(tid, status) => setQueue(prev => prev.map(t => t.id === tid ? { ...t, status } : t))}
               />
            )}

            {activeTab === 'schedule' && (
               <StaffScheduleManager 
                  scheduleData={scheduleData}
                  onUpdateData={setScheduleData}
               />
            )}

            {activeTab === 'form_manager' && (
               <FormManager 
                  forms={forms}
                  onCreateForm={() => {
                     const newForm: FormTemplate = {
                        id: crypto.randomUUID(),
                        shareToken: crypto.randomUUID().slice(0, 8),
                        title: '未命名表单',
                        description: '',
                        status: 'DRAFT',
                        createdDate: new Date().toLocaleDateString(),
                        submissionCount: 0,
                        fields: [],
                        themeColor: 'blue'
                     };
                     setForms(prev => [newForm, ...prev]);
                     setSelectedFormId(newForm.id);
                     setDesignerMode('EDIT');
                     setActiveTab('form_designer');
                  }}
                  onSelectForm={(id, mode) => {
                     setSelectedFormId(id);
                     setDesignerMode(mode);
                     setActiveTab('form_designer');
                  }}
                  onDeleteForm={(id) => setForms(prev => prev.filter(f => f.id !== id))}
                  onToggleStatus={(id, status) => setForms(prev => prev.map(f => f.id === id ? { ...f, status } : f))}
               />
            )}

            {activeTab === 'form_designer' && selectedFormId && (
               designerMode === 'EDIT' ? (
                  <FormDesigner 
                     form={forms.find(f => f.id === selectedFormId)!}
                     onSave={(updated) => setForms(prev => prev.map(f => f.id === updated.id ? updated : f))}
                     onBack={() => setActiveTab('form_manager')}
                     onPublish={() => {
                        setForms(prev => prev.map(f => f.id === selectedFormId ? { ...f, status: 'ACTIVE' } : f));
                        setDesignerMode('PREVIEW');
                     }}
                  />
               ) : designerMode === 'ANALYTICS' ? (
                  <FormAnalytics 
                     form={forms.find(f => f.id === selectedFormId)!}
                     submissions={formSubmissions.filter(s => s.formId === selectedFormId)}
                     onBack={() => setActiveTab('form_manager')}
                     onDeleteSubmission={(sid) => setFormSubmissions(prev => prev.filter(s => s.id !== sid))}
                     onShare={() => setDesignerMode('PREVIEW')}
                  />
               ) : (
                  <FormShareDashboard 
                     form={forms.find(f => f.id === selectedFormId)!}
                     onBack={() => setActiveTab('form_manager')}
                     onPreview={() => {
                        // Launch simulation in new tab logic or overlay
                        setActiveTab('public_view_simulation');
                     }}
                     customDomain={loginConfig.title} // Misuse of title for domain for demo
                  />
               )
            )}

            {activeTab === 'interview' && (
               <Interview 
                  onSaveSession={(sess) => setInterviewSessions(prev => [sess, ...prev])}
               />
            )}

            {activeTab === 'talent_pool' && (
               <TalentPool 
                  staffList={staffList}
                  registrationList={[...registrationList, ...onSiteRecords]}
                  onUpdateStaff={(s) => setStaffList(prev => prev.map(old => old.id === s.id ? s : old))}
                  onUpdateRegistration={(list) => {
                     // Need to update master list and onsite list based on ID
                     const listIds = new Set(list.map(r => r.id));
                     setRegistrationList(prev => prev.map(r => listIds.has(r.id) ? (list.find(n => n.id === r.id) || r) : r));
                     setOnSiteRecords(prev => prev.map(r => listIds.has(r.id) ? (list.find(n => n.id === r.id) || r) : r));
                  }}
               />
            )}

            {activeTab === 'attendance_reports' && (
               <AttendanceReports 
                  staffList={staffList}
                  groups={groups}
                  allRecords={attendanceRecords}
                  session={session}
                  permissionSettings={permissionSettings}
                  attendanceConfig={attendanceConfig}
                  onUpdateOrAddRecord={(staffId, date, type, time) => {
                     // Find existing and update or create new
                     // Simplified logic for demo
                     const existing = attendanceRecords.find(r => r.staffId === staffId && r.timestamp.startsWith(date) && r.type === type);
                     const fullTime = `${date}T${time}:00.000Z`; // Basic ISO construction
                     if (existing) {
                        setAttendanceRecords(prev => prev.map(r => r.id === existing.id ? { ...r, timestamp: fullTime, isManual: true } : r));
                     } else {
                        handleClockIn('', 'NORMAL', fullTime); // Reuse handler
                     }
                  }}
               />
            )}

            {activeTab === 'announcements' && (
               <AnnouncementManager 
                  currentUserRole={session.role}
                  currentUserGroups={session.staff?.roles.filter(r => r.isLeader) || []}
                  announcements={announcements}
                  onAddAnnouncement={(a) => setAnnouncements(prev => [a, ...prev])}
                  onDeleteAnnouncement={(id) => setAnnouncements(prev => prev.filter(a => a.id !== id))}
                  currentUserName={session.staff?.name || 'Admin'}
               />
            )}

            {activeTab === 'settings' && (
               <SystemSettings 
                  onSave={(settings) => {
                     setAttendanceConfig(settings.attendance);
                     setPermissionSettings(settings.permissions);
                     setLoginConfig(settings.loginConfig);
                     setRegistrationConfig(settings.registrationConfig);
                  }}
                  initialDomain=""
                  initialAttendanceConfig={attendanceConfig}
                  initialPermissionSettings={permissionSettings}
                  initialLoginConfig={loginConfig}
                  initialRegistrationConfig={registrationConfig}
                  adminUsers={adminUsers}
                  onAddAdmin={(u) => { setAdminUsers(prev => [...prev, u]); return true; }}
                  onDeleteAdmin={(u) => setAdminUsers(prev => prev.filter(a => a.username !== u))}
                  onUpdateAdminPassword={(u, p) => setAdminUsers(prev => prev.map(a => a.username === u ? { ...a, password: p } : a))}
               />
            )}

            {activeTab === 'all_staff_overview' && (
               <AllStaffOverview 
                  groups={groups}
                  staffList={staffList}
                  viewMode={session.role === 'ADMIN' || permissionSettings.allowStaffViewTeam ? 'STRUCTURED' : 'FLAT'}
               />
            )}

         </div>
      </main>
    </div>
  );
};

export default App;
